use std::fs;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use notify::{RecommendedWatcher, RecursiveMode, Watcher};
use tokio::fs as tokio_fs;
use tokio::sync::Mutex;
use log::{info, error};
use std::time::SystemTime;
use std::io;

#[derive(Debug)]
struct BackupManager {
    source_dir: PathBuf,
    backup_dir: PathBuf,
    rollback_dir: PathBuf,
    watcher: RecommendedWatcher,
}

impl BackupManager {
    async fn new(source_dir: PathBuf, backup_dir: PathBuf) -> io::Result<Self> {
        let rollback_dir = backup_dir.join("rollback");
        fs::create_dir_all(&rollback_dir)?;
        fs::create_dir_all(&backup_dir)?;

        let (tx, rx) = std::sync::mpsc::channel();
        let watcher = notify::recommended_watcher(tx)?;

        Ok(Self {
            source_dir,
            backup_dir,
            rollback_dir,
            watcher,
        })
    }

    async fn start(&mut self) -> io::Result<()> {
        self.watcher.watch(&self.source_dir, RecursiveMode::Recursive)?;
        info!("Started watching directory: {:?}", self.source_dir);

        for event in self.watcher {
            match event {
                Ok(event) => {
                    self.handle_event(event).await?;
                }
                Err(e) => error!("Watch error: {:?}", e),
            }
        }

        Ok(())
    }

    async fn handle_event(&self, event: notify::Event) -> io::Result<()> {
        for path in event.paths {
            let relative_path = path.strip_prefix(&self.source_dir)?;
            let backup_path = self.backup_dir.join(relative_path);
            let rollback_path = self.rollback_dir.join(relative_path);

            match event.kind {
                notify::EventKind::Create(_) | notify::EventKind::Modify(_) => {
                    self.sync_file(&path, &backup_path, &rollback_path).await?;
                }
                notify::EventKind::Remove(_) => {
                    self.handle_removal(&backup_path, &rollback_path).await?;
                }
                _ => {}
            }
        }
        Ok(())
    }

    async fn sync_file(
        &self,
        source_path: &Path,
        backup_path: &Path,
        rollback_path: &Path,
    ) -> io::Result<()> {
        if backup_path.exists() {
            tokio_fs::copy(&backup_path, &rollback_path).await?;
        }

        tokio_fs::copy(&source_path, &backup_path).await?;
        info!("Synced file: {:?} -> {:?}", source_path, backup_path);
        Ok(())
    }

    async fn handle_removal(&self, backup_path: &Path, rollback_path: &Path) -> io::Result<()> {
        if backup_path.exists() {
            tokio_fs::copy(&backup_path, &rollback_path).await?;
            tokio_fs::remove_file(&backup_path).await?;
            info!("Removed file from backup: {:?}", backup_path);
        }
        Ok(())
    }

    async fn rollback(&self) -> io::Result<()> {
        for entry in fs::read_dir(&self.rollback_dir)? {
            let entry = entry?;
            let relative_path = entry.path().strip_prefix(&self.rollback_dir)?;
            let backup_path = self.backup_dir.join(relative_path);

            tokio_fs::copy(&entry.path(), &backup_path).await?;
            info!("Rolled back file: {:?} -> {:?}", entry.path(), backup_path);
        }
        Ok(())
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    env_logger::init();

    let source_dir = PathBuf::from("./source");
    let backup_dir = PathBuf::from("./backup");

    let mut manager = BackupManager::new(source_dir, backup_dir).await?;
    manager.start().await?;

    Ok(())
}
