use std::fs;
use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::thread;
use std::time::Duration;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <directory>", args[0]);
        std::process::exit(1);
    }

    let dir_path = Path::new(&args[1]);
    if !dir_path.is_dir() {
        eprintln!("Error: '{}' is not a directory", dir_path.display());
        std::process::exit(1);
    }

    let (tx, rx) = mpsc::channel();

    // Spawn a thread to monitor directory changes
    let tx_clone = tx.clone();
    thread::spawn(move || {
        monitor_directory(dir_path, tx_clone).unwrap();
    });

    // Spawn worker threads to process file changes
    for _ in 0..4 {
        let rx_clone = rx.clone();
        thread::spawn(move || {
            process_files(rx_clone);
        });
    }

    println!("Monitoring directory: {}", dir_path.display());
    loop {
        thread::sleep(Duration::from_secs(1));
    }
}

fn monitor_directory(dir_path: &Path, tx: mpsc::Sender<PathBuf>) -> std::io::Result<()> {
    loop {
        let entries = fs::read_dir(dir_path)?;
        for entry in entries {
            let entry = entry?;
            let path = entry.path();
            if path.is_file() {
                tx.send(path).unwrap();
            }
        }
        thread::sleep(Duration::from_secs(1));
    }
}

fn process_files(rx: mpsc::Receiver<PathBuf>) {
    while let Ok(file_path) = rx.recv() {
        if let Some(ext) = file_path.extension() {
            let ext_dir = file_path.parent().unwrap().join(ext);
            if !ext_dir.exists() {
                fs::create_dir(&ext_dir).unwrap();
            }
            let new_path = ext_dir.join(file_path.file_name().unwrap());
            fs::rename(&file_path, &new_path).unwrap();
        }
    }
}
