use std::fs::File;
use std::io::{self, Read, Write};
use std::path::Path;
use std::sync::{Arc, Mutex};
use serde::{Deserialize, Serialize};
use tokio::task;

#[derive(Debug, Serialize, Deserialize)]
struct InventoryItem {
    store_id: String,
    product_id: String,
    quantity: u32,
}

#[derive(Debug, Serialize, Deserialize)]
struct InventoryData {
    inventories: Vec<InventoryItem>,
}

async fn load_inventory_data(path: &str) -> io::Result<InventoryData> {
    let mut file = File::open(path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;
    let data: InventoryData = serde_json::from_str(&contents)?;
    Ok(data)
}

async fn save_inventory_data(path: &str, data: &InventoryData) -> io::Result<()> {
    let json = serde_json::to_string_pretty(data)?;
    let mut file = File::create(path)?;
    file.write_all(json.as_bytes())?;
    Ok(())
}

async fn update_inventory(
    inventory_data: Arc<Mutex<InventoryData>>,
    store_id: String,
    product_id: String,
    quantity_change: i32,
) {
    let mut data = inventory_data.lock().unwrap();
    if let Some(item) = data
        .inventories
        .iter_mut()
        .find(|i| i.store_id == store_id && i.product_id == product_id)
    {
        if quantity_change < 0 {
            let abs_change = quantity_change.abs() as u32;
            if item.quantity >= abs_change {
                item.quantity -= abs_change;
            } else {
                item.quantity = 0;
            }
        } else {
            item.quantity += quantity_change as u32;
        }
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let path = "inventory.json";
    let inventory_data = Arc::new(Mutex::new(load_inventory_data(path).await?));

    println!("Current inventory loaded. Enter updates in format: store_id product_id quantity_change (or 'quit' to exit)");

    loop {
        let mut input = String::new();
        io::stdin().read_line(&mut input)?;
        let input = input.trim();

        if input == "quit" {
            break;
        }

        let parts: Vec<&str> = input.split_whitespace().collect();
        if parts.len() != 3 {
            println!("Invalid input format. Use: store_id product_id quantity_change");
            continue;
        }

        let store_id = parts[0].to_string();
        let product_id = parts[1].to_string();
        let quantity_change: i32 = match parts[2].parse() {
            Ok(val) => val,
            Err(_) => {
                println!("Invalid quantity change. Must be a number.");
                continue;
            }
        };

        let data_clone = Arc::clone(&inventory_data);
        task::spawn(async move {
            update_inventory(data_clone, store_id, product_id, quantity_change).await;
        });
    }

    save_inventory_data(path, &inventory_data.lock().unwrap()).await?;
    println!("Inventory updated and saved to {}", path);
    Ok(())
}
