use std::fs::{File, OpenOptions};
use std::io::{self, BufRead, BufReader, Seek, SeekFrom};
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};
use serde_json::Value;
use std::collections::HashMap;
use thiserror::Error;

#[derive(Error, Debug)]
enum LogError {
    #[error("IO error: {0}")]
    Io(#[from] io::Error),
    #[error("JSON parse error: {0}")]
    Json(#[from] serde_json::Error),
}

struct LogMetrics {
    error_count: u64,
    total_response_time: u64,
    request_count: u64,
}

impl Default for LogMetrics {
    fn default() -> Self {
        LogMetrics {
            error_count: 0,
            total_response_time: 0,
            request_count: 0,
        }
    }
}

fn process_log_line(line: &str, metrics: &mut LogMetrics) -> Result<(), LogError> {
    let log_data: Value = serde_json::from_str(line)?;

    if let Some(status) = log_data["status"].as_str() {
        if status.starts_with("5") || status.starts_with("4") {
            metrics.error_count += 1;
        }
    }

    if let Some(response_time) = log_data["response_time"].as_u64() {
        metrics.total_response_time += response_time;
        metrics.request_count += 1;
    }

    Ok(())
}

fn monitor_log_file(
    path: &Path,
    shared_metrics: Arc<Mutex<HashMap<String, LogMetrics>>>,
) -> Result<(), LogError> {
    let mut file = OpenOptions::new().read(true).open(path)?;
    let mut reader = BufReader::new(file);
    let mut buffer = String::new();

    loop {
        let bytes_read = reader.read_line(&mut buffer)?;
        if bytes_read == 0 {
            thread::sleep(Duration::from_millis(100));
            continue;
        }

        let server_id = path.file_name().unwrap().to_str().unwrap().to_string();
        let mut metrics = shared_metrics.lock().unwrap();
        let server_metrics = metrics.entry(server_id).or_default();

        if let Err(e) = process_log_line(&buffer, server_metrics) {
            eprintln!("Error processing log line: {}", e);
        }

        buffer.clear();
    }
}

fn aggregate_metrics(shared_metrics: Arc<Mutex<HashMap<String, LogMetrics>>>) {
    loop {
        thread::sleep(Duration::from_secs(5));
        let metrics = shared_metrics.lock().unwrap();

        println!("\n=== Metrics Summary ===");
        for (server, stats) in metrics.iter() {
            let error_rate = if stats.request_count > 0 {
                (stats.error_count as f64 / stats.request_count as f64) * 100.0
            } else {
                0.0
            };

            let avg_response_time = if stats.request_count > 0 {
                stats.total_response_time as f64 / stats.request_count as f64
            } else {
                0.0
            };

            println!(
                "Server {}: Error Rate: {:.2}%, Avg Response Time: {:.2}ms",
                server, error_rate, avg_response_time
            );
        }
    }
}

fn main() -> Result<(), LogError> {
    let shared_metrics = Arc::new(Mutex::new(HashMap::new()));
    let metrics_clone = shared_metrics.clone();

    // Spawn aggregation thread
    thread::spawn(move || {
        aggregate_metrics(metrics_clone);
    });

    // Simulate monitoring multiple log files (replace with actual paths)
    let log_paths = (1..=100).map(|i| format!("server_{}.log", i).into());

    let mut handles = vec![];
    for path in log_paths {
        let shared = shared_metrics.clone();
        let handle = thread::spawn(move || {
            if let Err(e) = monitor_log_file(&path, shared) {
                eprintln!("Error monitoring {}: {}", path.display(), e);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    Ok(())
}
