import java.util.function.*;
import java.util.stream.*;

import jdk.incubator.concurrent.*;

public class SentimentAnalysisServer {
    private static final int PORT = 8080;
    private static final ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();

    public static void main(String[] args) throws IOException {
        try (var serverSocket = new ServerSocket(PORT)) {
            System.out.println("Server listening on port " + PORT);
            while (true) {
                var socket = serverSocket.accept();
                executor.submit(() -> handleRequest(socket));
            }
        }
    }

    private static void handleRequest(Socket socket) {
        try (var in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
             var out = new BufferedWriter(new OutputStreamWriter(socket.getOutputStream()))) {

            var request = readRequest(in);
            var text = extractText(request);
            var sentiment = analyzeSentiment(text);

            var response = new SentimentResponse(sentiment);
            sendResponse(out, response);
        } catch (IOException e) {
            e.printStackTrace();
        } finally {
            try { socket.close(); } catch (IOException ignored) {}
        }
    }

    private static String readRequest(BufferedReader in) throws IOException {
        var request = new StringBuilder();
        String line;
        while ((line = in.readLine()) != null && !line.isEmpty()) {
            request.append(line).append("\n");
        }
        return request.toString();
    }

    private static String extractText(String request) {
        var lines = request.lines().toList();
        var lastLine = lines.get(lines.size() - 1);
        return lastLine.trim();
    }

    private static String analyzeSentiment(String text) {
        var positiveWords = Set.of("happy", "good", "great", "awesome", "love");
        var negativeWords = Set.of("sad", "bad", "terrible", "hate", "awful");

        long positiveCount = Arrays.stream(text.split("\\s+"))
            .filter(positiveWords::contains)
            .count();

        long negativeCount = Arrays.stream(text.split("\\s+"))
            .filter(negativeWords::contains)
            .count();

        if (positiveCount > negativeCount) return "positive";
        if (negativeCount > positiveCount) return "negative";
        return "neutral";
    }

    private static void sendResponse(BufferedWriter out, SentimentResponse response) throws IOException {
        out.write("HTTP/1.1 200 OK\r\n");
        out.write("Content-Type: application/json\r\n");
        out.write("\r\n");
        out.write(response.toJson());
        out.flush();
    }

    inline record SentimentResponse(String sentiment) {
        String toJson() {
            return String.format("{\"sentiment\": \"%s\"}", sentiment);
        }
    }
}
