use std::{
    collections::HashMap,
    sync::{Arc, Mutex},
};
use tokio::{
    io::{AsyncBufReadExt, AsyncWriteExt, BufReader},
    net::{TcpListener, TcpStream},
    sync::broadcast,
};
use tokio_tungstenite::tungstenite::protocol::Message;

#[tokio::main]
async fn main() {
    let listener = TcpListener::bind("127.0.0.1:8080").await.unwrap();
    println!("WebSocket server running on ws://127.0.0.1:8080");

    let (tx, _rx) = broadcast::channel::<(String, String)>(100);
    let clients: Arc<Mutex<HashMap<String, broadcast::Sender<String>>>> =
        Arc::new(Mutex::new(HashMap::new()));
    let history_file = "chat_history.log";

    while let Ok((stream, _)) = listener.accept().await {
        let tx = tx.clone();
        let clients = clients.clone();
        tokio::spawn(async move {
            handle_connection(stream, tx, clients, history_file).await;
        });
    }
}

async fn handle_connection(
    stream: TcpStream,
    tx: broadcast::Sender<(String, String)>,
    clients: Arc<Mutex<HashMap<String, broadcast::Sender<String>>>>,
    history_file: &str,
) {
    let addr = stream.peer_addr().unwrap().to_string();
    println!("New connection: {}", addr);

    let (ws_stream, _) = tokio_tungstenite::accept_async(stream).await.unwrap();
    let (mut ws_sender, mut ws_receiver) = ws_stream.split();

    let (client_tx, mut client_rx) = broadcast::channel::<String>(10);
    clients.lock().unwrap().insert(addr.clone(), client_tx);

    let mut tx_task = tokio::spawn(async move {
        while let Ok(msg) = client_rx.recv().await {
            if ws_sender
                .send(Message::Text(msg))
                .await
                .is_err()
            {
                break;
            }
        }
    });

    let rx_task = tokio::spawn(async move {
        while let Some(Ok(msg)) = ws_receiver.next().await {
            if let Message::Text(text) = msg {
                let parts: Vec<&str> = text.splitn(2, ':').collect();
                if parts.len() == 2 {
                    let recipient = parts[0].trim();
                    let message = parts[1].trim();
                    tx.send((recipient.to_string(), message.to_string()))
                        .unwrap();
                    log_message(history_file, &addr, recipient, message).await;
                }
            }
        }
    });

    tokio::select! {
        _ = (&mut tx_task) => rx_task.abort(),
        _ = rx_task => tx_task.abort(),
    }

    clients.lock().unwrap().remove(&addr);
    println!("Connection closed: {}", addr);
}

async fn log_message(file_path: &str, sender: &str, recipient: &str, message: &str) {
    use tokio::fs::OpenOptions;
    use tokio::io::AsyncWriteExt;

    let log_entry = format!("{} -> {}: {}\n", sender, recipient, message);
    let mut file = OpenOptions::new()
        .create(true)
        .append(true)
        .open(file_path)
        .await
        .unwrap();

    file.write_all(log_entry.as_bytes()).await.unwrap();
}
