    private static final Logger logger = Logger.getLogger(DataRetentionService.class.getName());
    private final Map<String, Duration> retentionPolicies = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
    private final Supplier<Connection> sqlConnectionSupplier;
    private final Supplier<Object> nosqlConnectionSupplier;

    public DataRetentionService(Supplier<Connection> sqlConnectionSupplier, Supplier<Object> nosqlConnectionSupplier) {
        this.sqlConnectionSupplier = sqlConnectionSupplier;
        this.nosqlConnectionSupplier = nosqlConnectionSupplier;
    }

    public void setRetentionPolicy(String tableName, Duration duration) {
        retentionPolicies.put(tableName, duration);
    }

    public void start() {
        scheduler.scheduleAtFixedRate(this::enforceRetentionPolicies, 0, 1, TimeUnit.DAYS);
    }

    private void enforceRetentionPolicies() {
        retentionPolicies.forEach((table, duration) -> {
            try {
                purgeData(table, duration);
            } catch (Exception e) {
                logger.log(Level.SEVERE, "Failed to enforce retention policy for table: " + table, e);
            }
        });
    }

    private void purgeData(String table, Duration duration) throws Exception {
        Object connection = sqlConnectionSupplier.get();
        if (connection instanceof Connection sqlConn) {
            purgeSQLData(sqlConn, table, duration);
        } else {
            Object nosqlConn = nosqlConnectionSupplier.get();
            purgeNoSQLData(nosqlConn, table, duration);
        }
    }

    private void purgeSQLData(Connection connection, String table, Duration duration) throws SQLException {
        LocalDateTime cutoff = LocalDateTime.now().minus(duration);
        String sql = "DELETE FROM " + table + " WHERE timestamp_column < ?";
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.setTimestamp(1, Timestamp.valueOf(cutoff));
            int rows = stmt.executeUpdate();
            logger.info("Purged " + rows + " rows from " + table);
        }
    }

    private void purgeNoSQLData(Object connection, String table, Duration duration) {
        // Placeholder for NoSQL implementation - would vary by database
        logger.warning("NoSQL data purging not implemented for table: " + table);
    }

    public void stop() {
        scheduler.shutdown();
    }

    // Example usage
    public static void main(String[] args) {
        DataRetentionService service = new DataRetentionService(
            () -> DriverManager.getConnection("jdbc:mysql://localhost:3306/db", "user", "pass"),
            () -> null // Replace with actual NoSQL connection supplier
        );

        service.setRetentionPolicy("user_logs", Duration.ofDays(30));
        service.setRetentionPolicy("audit_trail", Duration.ofDays(365));
