import java.net.InetSocketAddress;
import java.nio.ByteBuffer;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import org.java_websocket.WebSocket;
import org.java_websocket.handshake.ClientHandshake;
import org.java_websocket.server.WebSocketServer;

public class WebSocketServerApp extends WebSocketServer {
    private static final ConcurrentHashMap<WebSocket, String> clients = new ConcurrentHashMap<>();
    private static final ExecutorService executor = Executors.newCachedThreadPool();

    public WebSocketServerApp(InetSocketAddress address) {
        super(address);
    }

    @Override
    public void onOpen(WebSocket conn, ClientHandshake handshake) {
        clients.put(conn, "Client-" + conn.getRemoteSocketAddress());
        System.out.println("New connection: " + conn.getRemoteSocketAddress());
    }

    @Override
    public void onClose(WebSocket conn, int code, String reason, boolean remote) {
        clients.remove(conn);
        System.out.println("Closed connection: " + conn.getRemoteSocketAddress());
    }

    @Override
    public void onMessage(WebSocket conn, String message) {
        CompletableFuture.runAsync(() -> {
            String processedMsg = processMessage(message);
            broadcast(processedMsg);
        }, executor).exceptionally(ex -> {
            System.err.println("Error processing message: " + ex.getMessage());
            return null;
        });
    }

    @Override
    public void onMessage(WebSocket conn, ByteBuffer message) {
        CompletableFuture.runAsync(() -> {
            String msg = new String(message.array());
            String processedMsg = processMessage(msg);
            broadcast(processedMsg);
        }, executor).exceptionally(ex -> {
            System.err.println("Error processing binary message: " + ex.getMessage());
            return null;
        });
    }

    @Override
    public void onError(WebSocket conn, Exception ex) {
        System.err.println("Error occurred: " + ex.getMessage());
        if (conn != null) {
            clients.remove(conn);
        }
    }

    private String processMessage(String message) {
        return "Processed: " + message;
    }

    private void broadcast(String message) {
        clients.keySet().forEach(client -> {
            if (client.isOpen()) {
                client.send(message);
            }
        });
    }

    public static void main(String[] args) {
        String host = "localhost";
        int port = 8080;
        WebSocketServerApp server = new WebSocketServerApp(new InetSocketAddress(host, port));
        server.run();
        System.out.println("WebSocket server started on ws://" + host + ":" + port);
    }
}
