import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.sql.Statement;
import java.util.ArrayList;

public class StockAnalyzer {
    private static final Logger logger = Logger.getLogger(StockAnalyzer.class.getName());
    private static final String API_URL = "https://api.example.com/financial/data"; // Replace with actual API
    private static final String DB_URL = "jdbc:sqlite:stock_data.db";

    public static void main(String[] args) {
        try {
            String jsonResponse = fetchStockData();
            List<StockData> stockDataList = parseJsonResponse(jsonResponse);
            analyzeAndStoreData(stockDataList);
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error in StockAnalyzer: " + e.getMessage(), e);
        }
    }

    private static String fetchStockData() throws Exception {
        HttpClient client = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(10))
                .build();

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(API_URL))
                .GET()
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        logger.info("Fetched stock data from API");
        return response.body();
    }

    private static List<StockData> parseJsonResponse(String jsonResponse) {
        List<StockData> stockDataList = new ArrayList<>();
        JSONArray jsonArray = new JSONArray(jsonResponse);

        for (int i = 0; i < jsonArray.length(); i++) {
            JSONObject jsonObject = jsonArray.getJSONObject(i);
            StockData data = new StockData(
                    jsonObject.getString("symbol"),
                    jsonObject.getDouble("price"),
                    jsonObject.getLong("timestamp")
            );
            stockDataList.add(data);
        }
        logger.info("Parsed JSON response into StockData objects");
        return stockDataList;
    }

    private static void analyzeAndStoreData(List<StockData> stockDataList) {
        if (stockDataList.isEmpty()) {
            logger.warning("No stock data to analyze");
            return;
        }

        double sum = 0;
        double max = Double.MIN_VALUE;
        double min = Double.MAX_VALUE;

        for (StockData data : stockDataList) {
            double price = data.getPrice();
            sum += price;
            max = Math.max(max, price);
            min = Math.min(min, price);
        }

        double average = sum / stockDataList.size();
        String symbol = stockDataList.get(0).getSymbol(); // Assuming same symbol for all data

        logger.info(String.format("Analysis: Symbol=%s, Avg=%.2f, Max=%.2f, Min=%.2f", 
                symbol, average, max, min));

        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            createTableIfNotExists(conn);

            String sql = "INSERT INTO stock_analysis(symbol, average_price, max_price, min_price, timestamp) VALUES(?,?,?,?,?)";
            try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                pstmt.setString(1, symbol);
                pstmt.setDouble(2, average);
                pstmt.setDouble(3, max);
                pstmt.setDouble(4, min);
                pstmt.setLong(5, System.currentTimeMillis());
                pstmt.executeUpdate();
                logger.info("Stored analysis results in database");
            }
        } catch (SQLException e) {
            logger.log(Level.SEVERE, "Database error: " + e.getMessage(), e);
        }
    }

    private static void createTableIfNotExists(Connection conn) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS stock_analysis (" +
                "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                "symbol TEXT NOT NULL," +
                "average_price REAL NOT NULL," +
                "max_price REAL NOT NULL," +
                "min_price REAL NOT NULL," +
                "timestamp INTEGER NOT NULL)";

        try (Statement stmt = conn.createStatement()) {
            stmt.execute(sql);
        }
    }

    static class StockData {
        private final String symbol;
        private final double price;
        private final long timestamp;

        public StockData(String symbol, double price, long timestamp) {
            this.symbol = symbol;
            this.price = price;
            this.timestamp = timestamp;
        }

        public String getSymbol() { return symbol; }
        public double getPrice() { return price; }
        public long getTimestamp() { return timestamp; }
    }
}
