import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.function.*;
import java.util.stream.*;

public class CSVProcessor {
    private static final int BUFFER_SIZE = 8192;

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java CSVProcessor <config_file> <csv_file>");
            return;
        }

        String configFile = args[0];
        String csvFile = args[1];

        try {
            Map<String, Integer> columnOrder = loadConfig(configFile);
            processCSV(csvFile, columnOrder);
        } catch (IOException e) {
            System.err.println("Error processing files: " + e.getMessage());
        }
    }

    private static Map<String, Integer> loadConfig(String configFile) throws IOException {
        return Files.lines(Paths.get(configFile))
            .filter(line -> !line.trim().isEmpty())
            .collect(Collectors.toMap(
                (var line) -> line.split("=")[0].trim(),
                (var line) -> Integer.parseInt(line.split("=")[1].trim())
            ));
    }

    private static void processCSV(String csvFile, Map<String, Integer> columnOrder) throws IOException {
        Path inputPath = Paths.get(csvFile);
        Path outputPath = Paths.get("processed_" + csvFile);

        try (BufferedReader reader = Files.newBufferedReader(inputPath);
             BufferedWriter writer = Files.newBufferedWriter(outputPath)) {

            String headerLine = reader.readLine();
            if (headerLine == null) return;

            String[] headers = headerLine.split(",");
            int[] newIndices = getNewIndices(headers, columnOrder);

            writer.write(String.join(",", Arrays.stream(headers)
                .sorted(Comparator.comparingInt((var header) -> columnOrder.getOrDefault(header, Integer.MAX_VALUE)))
                .toArray(String[]::new)));
            writer.newLine();

            Set<String> seenLines = new HashSet<>();
            String line;
            while ((line = reader.readLine()) != null) {
                if (!seenLines.contains(line)) {
                    seenLines.add(line);
                    String[] values = line.split(",");
                    String reorderedLine = reorderLine(values, newIndices);
                    writer.write(reorderedLine);
                    writer.newLine();
                }
            }
        }
    }

    private static int[] getNewIndices(String[] headers, Map<String, Integer> columnOrder) {
        List<String> sortedHeaders = Arrays.stream(headers)
            .sorted(Comparator.comparingInt((var header) -> columnOrder.getOrDefault(header, Integer.MAX_VALUE)))
            .collect(Collectors.toList());

        int[] newIndices = new int[headers.length];
        for (int i = 0; i < headers.length; i++) {
            newIndices[i] = sortedHeaders.indexOf(headers[i]);
        }
        return newIndices;
    }

    private static String reorderLine(String[] values, int[] newIndices) {
        String[] reordered = new String[values.length];
        for (int i = 0; i < values.length; i++) {
            reordered[newIndices[i]] = values[i];
        }
        return String.join(",", reordered);
    }
}
