use std::path::{Path, PathBuf};
use std::time::SystemTime;
use notify::{RecommendedWatcher, RecursiveMode, Watcher};
use tokio::sync::mpsc;
use async_std::task;
use lettre::transport::smtp::authentication::Credentials;
use lettre::{Message, SmtpTransport, Transport};
use serde::{Deserialize, Serialize};
use tokio::time::{sleep, Duration};

#[derive(Debug, Serialize, Deserialize)]
struct Config {
    directories: Vec<String>,
    email: EmailConfig,
    latency_ms: u64,
}

#[derive(Debug, Serialize, Deserialize)]
struct EmailConfig {
    smtp_server: String,
    smtp_username: String,
    smtp_password: String,
    from: String,
    to: String,
}

async fn watch_directory(path: PathBuf, tx: mpsc::Sender<(String, PathBuf, SystemTime)>) {
    let (watcher_tx, mut watcher_rx) = mpsc::channel(1);
    let mut watcher: RecommendedWatcher = Watcher::new_immediate(move |res| {
        if let Ok(event) = res {
            if let notify::EventKind::Create(_) = event.kind {
                for path in event.paths {
                    let _ = watcher_tx.blocking_send((
                        path.file_name().unwrap().to_str().unwrap().to_string(),
                        path.clone(),
                        SystemTime::now(),
                    ));
                }
            }
        }
    })
    .unwrap();

    watcher.watch(&path, RecursiveMode::NonRecursive).unwrap();

    while let Some((file_name, file_path, time)) = watcher_rx.recv().await {
        let _ = tx.send((file_name, file_path, time)).await;
    }
}

async fn send_email(
    email_config: &EmailConfig,
    file_name: String,
    file_path: PathBuf,
    time: SystemTime,
) {
    let email = Message::builder()
        .from(email_config.from.parse().unwrap())
        .to(email_config.to.parse().unwrap())
        .subject("New File Detected")
        .body(format!(
            "File: {}\nPath: {}\nTime: {:?}",
            file_name,
            file_path.display(),
            time
        ))
        .unwrap();

    let creds = Credentials::new(
        email_config.smtp_username.clone(),
        email_config.smtp_password.clone(),
    );

    let mailer = SmtpTransport::relay(&email_config.smtp_server)
        .unwrap()
        .credentials(creds)
        .build();

    let _ = mailer.send(&email);
}

#[tokio::main]
async fn main() {
    let config: Config = {
        let config_str = include_str!("config.toml");
        toml::from_str(config_str).unwrap()
    };

    let (tx, mut rx) = mpsc::channel(32);

    for dir in &config.directories {
        let path = Path::new(dir).to_path_buf();
        let tx_clone = tx.clone();
        tokio::spawn(async move {
            watch_directory(path, tx_clone).await;
        });
    }

    while let Some((file_name, file_path, time)) = rx.recv().await {
        send_email(&config.email, file_name, file_path, time).await;
        sleep(Duration::from_millis(config.latency_ms)).await;
    }
}
