import sqlite3
import json
from datetime import datetime
from typing import List, Dict, Optional, Union

class TaskManager:
    def __init__(self, db_path: str = "tasks.db"):
        self.db_path = db_path
        self._init_db()

    def _init_db(self) -> None:
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("""
                CREATE TABLE IF NOT EXISTS tasks (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    description TEXT NOT NULL,
                    deadline TEXT NOT NULL,
                    completed INTEGER DEFAULT 0
                )
            """)

    def _execute_query(self, query: str, params: tuple = (), commit: bool = False) -> Optional[sqlite3.Cursor]:
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.execute(query, params)
            if commit:
                conn.commit()
            return cursor

    def add_task(self, description: str, deadline: str) -> int:
        if not (task_id := self._execute_query(
            "INSERT INTO tasks (description, deadline) VALUES (?, ?) RETURNING id",
            (description, deadline),
            commit=True
        )):
            raise sqlite3.Error("Failed to add task")
        return task_id.fetchone()[0]

    def update_task(self, task_id: int, **kwargs) -> None:
        valid_fields = {"description", "deadline", "completed"}
        if not (fields := {k: v for k, v in kwargs.items() if k in valid_fields}):
            raise ValueError("No valid fields provided for update")

        query = "UPDATE tasks SET " + ", ".join(f"{k} = ?" for k in fields) + " WHERE id = ?"
        params = (*fields.values(), task_id)
        if not self._execute_query(query, params, commit=True):
            raise sqlite3.Error("Failed to update task")

    def delete_task(self, task_id: int) -> None:
        if not self._execute_query("DELETE FROM tasks WHERE id = ?", (task_id,), commit=True):
            raise sqlite3.Error("Failed to delete task")

    def get_tasks(self, **filters) -> List[Dict[str, Union[int, str, bool]]]:
        base_query = "SELECT id, description, deadline, completed FROM tasks"
        where_clause = ""
        params = ()

        if filters:
            valid_filters = {"completed": int, "deadline_before": str, "deadline_after": str}
            conditions = []
            for k, v in filters.items():
                if k == "completed":
                    conditions.append("completed = ?")
                    params += (v,)
                elif k == "deadline_before":
                    conditions.append("deadline < ?")
                    params += (v,)
                elif k == "deadline_after":
                    conditions.append("deadline > ?")
                    params += (v,)
            where_clause = " WHERE " + " AND ".join(conditions)

        query = base_query + where_clause
        if not (cursor := self._execute_query(query, params)):
            raise sqlite3.Error("Failed to fetch tasks")

        return [
            {
                "id": row[0],
                "description": row[1],
                "deadline": row[2],
                "completed": bool(row[3])
            }
            for row in cursor.fetchall()
        ]

    def get_tasks_json(self, **filters) -> str:
        return json.dumps(self.get_tasks(**filters), indent=2)

# Example usage
if __name__ == "__main__":
    tm = TaskManager()
    task_id = tm.add_task("Complete project", "2023-12-31")
    tm.update_task(task_id, completed=True)
    print(tm.get_tasks_json(completed=True))
