import asyncio
import os
import time
from datetime import datetime, timedelta
import aiohttp
import json

class CloudStorageBackup:
    def __init__(self, api_endpoint, api_key, local_dir, report_file="backup_report.json"):
        self.api_endpoint = api_endpoint
        self.api_key = api_key
        self.local_dir = local_dir
        self.report_file = report_file
        self.report = {
            "timestamp": datetime.now().isoformat(),
            "successful_backups": [],
            "failed_backups": [],
            "errors": []
        }

    async def upload_file(self, session, file_path):
        try:
            with open(file_path, 'rb') as file:
                async with session.post(
                    f"{self.api_endpoint}/upload",
                    headers={"Authorization": f"Bearer {self.api_key}"},
                    data={"file": file}
                ) as response:
                    if response.status == 200:
                        self.report["successful_backups"].append({
                            "file": file_path,
                            "timestamp": datetime.now().isoformat()
                        })
                    else:
                        self.report["failed_backups"].append({
                            "file": file_path,
                            "error": f"API returned status {response.status}",
                            "timestamp": datetime.now().isoformat()
                        })
        except Exception as e:
            self.report["failed_backups"].append({
                "file": file_path,
                "error": str(e),
                "timestamp": datetime.now().isoformat()
            })

    async def get_modified_files(self):
        modified_files = []
        cutoff_time = datetime.now() - timedelta(hours=24)
        try:
            for root, _, files in os.walk(self.local_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    mod_time = datetime.fromtimestamp(os.path.getmtime(file_path))
                    if mod_time > cutoff_time:
                        modified_files.append(file_path)
        except Exception as e:
            self.report["errors"].append({
                "error": f"Error accessing local files: {str(e)}",
                "timestamp": datetime.now().isoformat()
            })
        return modified_files

    async def save_report(self):
        try:
            with open(self.report_file, 'w') as f:
                json.dump(self.report, f, indent=2)
        except Exception as e:
            print(f"Failed to save report: {str(e)}")

    async def run_backup(self):
        try:
            modified_files = await self.get_modified_files()
            if not modified_files:
                self.report["errors"].append({
                    "error": "No modified files found in the last 24 hours",
                    "timestamp": datetime.now().isoformat()
                })
                return

            async with aiohttp.ClientSession() as session:
                tasks = [self.upload_file(session, file) for file in modified_files]
                await asyncio.gather(*tasks)

        except aiohttp.ClientError as e:
            self.report["errors"].append({
                "error": f"API connection error: {str(e)}",
                "timestamp": datetime.now().isoformat()
            })
        except Exception as e:
            self.report["errors"].append({
                "error": f"Unexpected error: {str(e)}",
                "timestamp": datetime.now().isoformat()
            })
        finally:
            await self.save_report()

if __name__ == "__main__":
    # Replace these with your actual values
    API_ENDPOINT = "https://api.cloudstorage.example.com"
    API_KEY = "your_api_key_here"
    LOCAL_DIR = "/path/to/local/files"

    backup = CloudStorageBackup(API_ENDPOINT, API_KEY, LOCAL_DIR)
    asyncio.run(backup.run_backup())
