use sysinfo::{System, SystemExt};

#[derive(Debug)]
struct ResourceUsage {
    timestamp: String,
    cpu_usage: f32,
    memory_used: u64,
    memory_total: u64,
    storage_used: u64,
    storage_total: u64,
}

impl ResourceUsage {
    fn to_csv_row(&self) -> String {
        format!(
            "{},{},{},{},{},{}\n",
            self.timestamp,
            self.cpu_usage,
            self.memory_used,
            self.memory_total,
            self.storage_used,
            self.storage_total
        )
    }
}

async fn log_resource_usage(file: &mut File) -> Result<(), IoError> {
    let mut sys = System::new_all();
    sys.refresh_all();

    let timestamp = chrono::Local::now().to_rfc3339();
    let cpu_usage = sys.global_cpu_info().cpu_usage();
    let memory_used = sys.used_memory();
    let memory_total = sys.total_memory();
    let storage_used = sys.total_memory() - sys.free_memory();
    let storage_total = sys.total_memory();

    let usage = ResourceUsage {
        timestamp,
        cpu_usage,
        memory_used,
        memory_total,
        storage_used,
        storage_total,
    };

    file.write_all(usage.to_csv_row().as_bytes())?;
    Ok(())
}

async fn monitor_resources() -> Result<(), Box<dyn std::error::Error>> {
    let mut file = OpenOptions::new()
        .create(true)
        .append(true)
        .open("resource_usage.csv")?;

    if file.metadata()?.len() == 0 {
        file.write_all("timestamp,cpu_usage,memory_used,memory_total,storage_used,storage_total\n".as_bytes())?;
    }

    let mut interval = time::interval(Duration::from_secs(60));
    loop {
        interval.tick().await;
        if let Err(e) = log_resource_usage(&mut file).await {
            eprintln!("Error logging resource usage: {}", e);
        }
    }
}

#[tokio::main]
async fn main() {
    if let Err(e) = monitor_resources().await {
        eprintln!("Monitoring error: {}", e);
    }
