import com.sun.management.OperatingSystemMXBean;
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import java.lang.management.MemoryUsage;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.HashMap;
import java.util.Map;
import com.google.gson.Gson;
import java.io.IOException;
import static java.net.http.HttpRequest.BodyPublishers.noBody;

public class JavaProcessMonitor {

    private static final Gson gson = new Gson();
    private static final HttpClient httpClient = HttpClient.newHttpClient();
    private static final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(4);

    public static void main(String[] args) {
        // Start REST API server
        startRestApiServer();
    }

    private static void startRestApiServer() {
        int port = 8080;
        HttpServer server = HttpServer.create(new InetSocketAddress(port), 0);
        server.createContext("/metrics", exchange -> {
            if ("GET".equals(exchange.getRequestMethod())) {
                Map<String, Object> metrics = getSystemMetrics();
                String response = gson.toJson(metrics);
                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.getBytes().length);
                exchange.getResponseBody().write(response.getBytes());
            } else {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
            }
            exchange.close();
        });
        server.setExecutor(scheduler);
        server.start();
        System.out.println("Server started on port " + port);
    }

    private static Map<String, Object> getSystemMetrics() {
        MemoryMXBean memoryBean = ManagementFactory.getMemoryMXBean();
        OperatingSystemMXBean osBean = ManagementFactory.getPlatformMXBean(OperatingSystemMXBean.class);
        MemoryUsage heapUsage = memoryBean.getHeapMemoryUsage();
        MemoryUsage nonHeapUsage = memoryBean.getNonHeapMemoryUsage();

        Map<String, Object> metrics = new HashMap<>();
        metrics.put("heapUsed", heapUsage.getUsed());
        metrics.put("heapCommitted", heapUsage.getCommitted());
        metrics.put("heapMax", heapUsage.getMax());
        metrics.put("nonHeapUsed", nonHeapUsage.getUsed());
        metrics.put("nonHeapCommitted", nonHeapUsage.getCommitted());
        metrics.put("cpuLoad", osBean.getProcessCpuLoad() * 100);
        metrics.put("systemCpuLoad", osBean.getSystemCpuLoad() * 100);
        metrics.put("availableProcessors", osBean.getAvailableProcessors());

        return metrics;
    }

    // Optional: Method to send metrics to another service
    private static void sendMetricsToService(String serviceUrl) {
        scheduler.scheduleAtFixedRate(() -> {
            Map<String, Object> metrics = getSystemMetrics();
            String jsonMetrics = gson.toJson(metrics);
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(serviceUrl))
                    .header("Content-Type", "application/json")
                    .POST(HttpRequest.BodyPublishers.ofString(jsonMetrics))
                    .build();
            try {
                HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
                System.out.println("Metrics sent: " + response.statusCode());
            } catch (IOException | InterruptedException e) {
                System.err.println("Failed to send metrics: " + e.getMessage());
            }
        }, 0, 5, TimeUnit.SECONDS);
    }
}
