public class ResourceMonitor {
    private static final String CONFIG_URL = "http://config-server.example.com/settings";
    private static final Path LOG_FILE = Paths.get("alerts.json");
    private static final Gson gson = new Gson();
    private static double cpuThreshold = 80.0;
    private static double memoryThreshold = 80.0;
    private static final HttpClient httpClient = HttpClient.newHttpClient();
    private static final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public static void main(String[] args) {
        scheduler.scheduleAtFixedRate(() -> {
            try {
                syncConfig();
                monitorResources();
            } catch (Exception e) {
                System.err.println("Error: " + e.getMessage());
            }
        }, 0, 5, TimeUnit.SECONDS);
    }

    private static void syncConfig() throws Exception {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(CONFIG_URL))
                .timeout(Duration.ofSeconds(10))
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
        JsonObject config = gson.fromJson(response.body(), JsonObject.class);
        cpuThreshold = config.get("cpuThreshold").getAsDouble();
        memoryThreshold = config.get("memoryThreshold").getAsDouble();
    }

    private static void monitorResources() throws Exception {
        OperatingSystemMXBean osBean = ManagementFactory.getPlatformMXBean(OperatingSystemMXBean.class);
        double cpuUsage = osBean.getCpuLoad() * 100;
        double memoryUsage = (1 - (double) osBean.getFreeMemorySize() / osBean.getTotalMemorySize()) * 100;

        if (cpuUsage > cpuThreshold) {
            logAlert("CPU", cpuUsage);
        }
        if (memoryUsage > memoryThreshold) {
            logAlert("Memory", memoryUsage);
        }
    }

    private static void logAlert(String resourceType, double usage) throws Exception {
        JsonObject alert = new JsonObject();
        alert.addProperty("timestamp", Instant.now().toString());
        alert.addProperty("resource", resourceType);
        alert.addProperty("utilization", usage);

        String logEntry = gson.toJson(alert) + System.lineSeparator();
        Files.write(LOG_FILE, logEntry.getBytes(), StandardOpenOption.CREATE, StandardOpenOption.APPEND);
    }
}
