use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::net::{TcpListener, TcpStream};
use std::io::{Read, Write};
use std::thread;

fn handle_client(
    mut stream: TcpStream,
    shared_map: Arc<Mutex<HashMap<String, i32>>>,
) -> std::io::Result<()> {
    let mut buffer = [0; 1024];
    stream.read(&mut buffer)?;

    let request = String::from_utf8_lossy(&buffer[..]);
    if !request.starts_with("POST") {
        stream.write_all(b"HTTP/1.1 405 Method Not Allowed\r\n\r\n")?;
        return Ok(());
    }

    let body_start = request.find("\r\n\r\n").unwrap_or(0) + 4;
    let body = &request[body_start..].trim_end_matches('\0');

    let parsed_json: Result<serde_json::Value, _> = serde_json::from_str(body);
    match parsed_json {
        Ok(json) => {
            if let Some(obj) = json.as_object() {
                let mut map = shared_map.lock().unwrap();
                for (key, value) in obj {
                    if let Some(num) = value.as_i64() {
                        map.insert(key.to_string(), num as i32);
                    }
                }
                stream.write_all(b"HTTP/1.1 200 OK\r\n\r\n")?;
            } else {
                eprintln!("Invalid JSON structure: expected object");
                stream.write_all(b"HTTP/1.1 400 Bad Request\r\n\r\n")?;
            }
        }
        Err(e) => {
            eprintln!("JSON parse error: {}", e);
            stream.write_all(b"HTTP/1.1 400 Bad Request\r\n\r\n")?;
        }
    }

    Ok(())
}

fn main() -> std::io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:8080")?;
    let shared_map = Arc::new(Mutex::new(HashMap::<String, i32>::new()));

    for stream in listener.incoming() {
        let shared_map = shared_map.clone();
        thread::spawn(move || {
            if let Err(e) = handle_client(stream.unwrap(), shared_map) {
                eprintln!("Error handling client: {}", e);
            }
        });
    }

    Ok(())
}
