import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.net.http.HttpResponse.BodyHandlers;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutionException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.sql.Statement;
import org.json.JSONArray;
import org.json.JSONObject;

public class AnalyticsEngine {
    private static final String API_URL = "https://api.example.com/transactions";
    private static final String DB_URL = "jdbc:sqlite:analytics.db";

    private final HttpClient httpClient;
    private Connection dbConnection;

    public AnalyticsEngine() {
        this.httpClient = HttpClient.newHttpClient();
        initializeDatabase();
    }

    private void initializeDatabase() {
        try {
            dbConnection = DriverManager.getConnection(DB_URL);
            Statement stmt = dbConnection.createStatement();
            stmt.execute("CREATE TABLE IF NOT EXISTS transaction_aggregates (" +
                         "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                         "total_amount REAL," +
                         "average_amount REAL," +
                         "max_amount REAL)");
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public CompletableFuture<Void> processTransactions() {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(API_URL))
                .header("Accept", "application/json")
                .build();

        return httpClient.sendAsync(request, BodyHandlers.ofString())
                .thenApply(HttpResponse::body)
                .thenApply(this::parseTransactions)
                .thenApplyAsync(this::aggregateData)
                .thenAccept(this::storeResults)
                .exceptionally(ex -> {
                    System.err.println("Error processing transactions: " + ex.getMessage());
                    return null;
                });
    }

    private JSONArray parseTransactions(String jsonResponse) {
        return new JSONArray(jsonResponse);
    }

    private AggregationResult aggregateData(JSONArray transactions) {
        double sum = 0;
        double max = Double.MIN_VALUE;
        int count = 0;

        for (int i = 0; i < transactions.length(); i++) {
            JSONObject transaction = transactions.getJSONObject(i);
            double amount = transaction.getDouble("amount");

            sum += amount;
            max = Math.max(max, amount);
            count++;
        }

        return new AggregationResult(
            sum,
            sum / count,
            max
        );
    }

    private void storeResults(AggregationResult result) {
        try {
            PreparedStatement stmt = dbConnection.prepareStatement(
                "INSERT INTO transaction_aggregates (total_amount, average_amount, max_amount) VALUES (?, ?, ?)");
            stmt.setDouble(1, result.totalAmount);
            stmt.setDouble(2, result.averageAmount);
            stmt.setDouble(3, result.maxAmount);
            stmt.executeUpdate();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public void close() {
        try {
            if (dbConnection != null) {
                dbConnection.close();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    private static class AggregationResult {
        final double totalAmount;
        final double averageAmount;
        final double maxAmount;

        AggregationResult(double totalAmount, double averageAmount, double maxAmount) {
            this.totalAmount = totalAmount;
            this.averageAmount = averageAmount;
            this.maxAmount = maxAmount;
        }
    }

    public static void main(String[] args) throws ExecutionException, InterruptedException {
        AnalyticsEngine engine = new AnalyticsEngine();
        engine.processTransactions().get();
        engine.close();
    }
}
