import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import net.sourceforge.tess4j.Tesseract;
import net.sourceforge.tess4j.TesseractException;

public class DirectoryMonitorOCR {
    private static final Logger logger = LogManager.getLogger(DirectoryMonitorOCR.class);
    private static final ExecutorService executor = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());
    private static final Tesseract tesseract = new Tesseract();

    public static void main(String[] args) throws IOException {
        if (args.length != 1) {
            logger.error("Usage: java DirectoryMonitorOCR <directory_path>");
            System.exit(1);
        }

        Path dir = Paths.get(args[0]);
        if (!Files.isDirectory(dir)) {
            logger.error("Invalid directory path: {}", dir);
            System.exit(1);
        }

        tesseract.setDatapath("tessdata"); // Update with your Tesseract data path

        try (WatchService watchService = FileSystems.getDefault().newWatchService()) {
            dir.register(watchService, StandardWatchEventKinds.ENTRY_CREATE);
            logger.info("Monitoring directory: {}", dir);

            while (true) {
                WatchKey key = watchService.take();
                for (WatchEvent<?> event : key.pollEvents()) {
                    if (event.kind() == StandardWatchEventKinds.ENTRY_CREATE) {
                        Path filePath = dir.resolve((Path) event.context());
                        executor.submit(() -> processImage(filePath));
                    }
                }
                key.reset();
            }
        } catch (InterruptedException e) {
            logger.error("Monitoring interrupted", e);
            Thread.currentThread().interrupt();
        } finally {
            executor.shutdown();
        }
    }

    private static void processImage(Path imagePath) {
        try {
            if (!isImageFile(imagePath)) {
                logger.warn("Skipping non-image file: {}", imagePath);
                return;
            }

            logger.info("Processing image: {}", imagePath);
            String extractedText = tesseract.doOCR(imagePath.toFile());
            String outputFilename = imagePath.getFileName().toString().replaceFirst("[.][^.]+$", "") + ".txt";
            Path outputPath = imagePath.getParent().resolve(outputFilename);

            Files.writeString(outputPath, extractedText);
            logger.info("Text extracted and saved to: {}", outputPath);
        } catch (TesseractException e) {
            logger.error("OCR failed for file: {}", imagePath, e);
        } catch (IOException e) {
            logger.error("File operation failed for: {}", imagePath, e);
        }
    }

    private static boolean isImageFile(Path path) {
        String filename = path.getFileName().toString().toLowerCase();
        return filename.endsWith(".jpg") || filename.endsWith(".jpeg") 
            || filename.endsWith(".png") || filename.endsWith(".bmp")
            || filename.endsWith(".gif") || filename.endsWith(".tiff");
    }
}
