public sealed interface Stock permits Stock.CommonStock, Stock.PreferredStock {
    record CommonStock(String symbol, double price) implements Stock {}
    record PreferredStock(String symbol, double price, double dividendYield) implements Stock {}
}

public final class MarketEvent {
    private final String message;
    private final long timestamp;

    public MarketEvent(String message) {
        this.message = message;
        this.timestamp = System.currentTimeMillis();
    }

    public String getMessage() {
        return message;
    }

    public long getTimestamp() {
        return timestamp;
    }
}

public class MarketSimulator {
    private final ExecutorService executor = Executors.newFixedThreadPool(4);
    private final HttpClient httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(5))
            .build();

    public void simulateMarketScenario(Stock[] stocks, String scenario) {
        executor.submit(() -> {
            switch (scenario.toLowerCase()) {
                case "bull" -> simulateBullMarket(stocks);
                case "bear" -> simulateBearMarket(stocks);
                case "crash" -> simulateMarketCrash(stocks);
                default -> throw new IllegalArgumentException("Unknown scenario: " + scenario);
            }
        });
    }

    private void simulateBullMarket(Stock[] stocks) {
        Random random = new Random();
        for (Stock stock : stocks) {
            double change = 1 + (random.nextDouble() * 0.1);
            Stock updatedStock = updateStockPrice(stock, change);
            sendMarketUpdate("Bull market: " + updatedStock);
        }
    }

    private void simulateBearMarket(Stock[] stocks) {
        Random random = new Random();
        for (Stock stock : stocks) {
            double change = 1 - (random.nextDouble() * 0.1);
            Stock updatedStock = updateStockPrice(stock, change);
            sendMarketUpdate("Bear market: " + updatedStock);
        }
    }

    private void simulateMarketCrash(Stock[] stocks) {
        for (Stock stock : stocks) {
            Stock updatedStock = updateStockPrice(stock, 0.5);
            sendMarketUpdate("Market crash: " + updatedStock);
        }
    }

    private Stock updateStockPrice(Stock stock, double multiplier) {
        return switch (stock) {
            case Stock.CommonStock common -> new Stock.CommonStock(
                    common.symbol(), common.price() * multiplier);
            case Stock.PreferredStock preferred -> new Stock.PreferredStock(
                    preferred.symbol(), preferred.price() * multiplier, preferred.dividendYield());
        };
    }

    private void sendMarketUpdate(String message) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create("http://example.com/api/updates"))
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(
                        "{\"message\":\"" + message + "\"}"))
                .build();

        httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApply(HttpResponse::body)
                .thenAccept(System.out::println);
    }

    public void shutdown() throws InterruptedException {
        executor.shutdown();
        executor.awaitTermination(5, TimeUnit.SECONDS);
    }

    public static void main(String[] args) {
        Stock[] portfolio = {
                new Stock.CommonStock("AAPL", 150.0),
                new Stock.PreferredStock("MSFT", 300.0, 0.02)
        };

        MarketSimulator simulator = new MarketSimulator();
        simulator.simulateMarketScenario(portfolio, "bull");

        try {
            Thread.sleep(2000);
            simulator.shutdown();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}
