import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;

import java.io.OutputStream;

public class CurrencyConverterAPI {

    private static final String EXCHANGE_RATE_API = "https://api.exchangerate-api.com/v4/latest/";
    private static final Map<String, CacheEntry> cache = new ConcurrentHashMap<>();
    private static final HttpClient httpClient = HttpClient.newHttpClient();

    public static void main(String[] args) throws Exception {
        HttpServer server = HttpServer.create(new java.net.InetSocketAddress(8080), 0);
        server.createContext("/convert", new ConvertHandler());
        server.setExecutor(null);
        server.start();
        System.out.println("Server started on port 8080");
    }

    static class ConvertHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"GET".equals(exchange.getRequestMethod())) {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
                return;
            }

            String query = exchange.getRequestURI().getQuery();
            Map<String, String> params = parseQuery(query);

            if (!params.containsKey("amount") || !params.containsKey("from") || !params.containsKey("to")) {
                exchange.sendResponseHeaders(400, -1); // Bad Request
                return;
            }

            try {
                double amount = Double.parseDouble(params.get("amount"));
                String fromCurrency = params.get("from").toUpperCase();
                String toCurrency = params.get("to").toUpperCase();

                double rate = getExchangeRate(fromCurrency, toCurrency);
                double convertedAmount = amount * rate;

                String response = String.format("{\"amount\": %.2f, \"from\": \"%s\", \"to\": \"%s\", \"convertedAmount\": %.2f}",
                        amount, fromCurrency, toCurrency, convertedAmount);

                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.length());
                OutputStream os = exchange.getResponseBody();
                os.write(response.getBytes());
                os.close();
            } catch (NumberFormatException e) {
                exchange.sendResponseHeaders(400, -1); // Bad Request
            } catch (Exception e) {
                exchange.sendResponseHeaders(500, -1); // Internal Server Error
            }
        }

        private Map<String, String> parseQuery(String query) {
            Map<String, String> params = new HashMap<>();
            if (query == null || query.isEmpty()) {
                return params;
            }
            for (String param : query.split("&")) {
                String[] pair = param.split("=");
                if (pair.length == 2) {
                    params.put(pair[0], pair[1]);
                }
            }
            return params;
        }

        private double getExchangeRate(String fromCurrency, String toCurrency) throws IOException, InterruptedException {
            String cacheKey = fromCurrency + "_" + toCurrency;
            CacheEntry cachedRate = cache.get(cacheKey);

            if (cachedRate != null && !cachedRate.isExpired()) {
                return cachedRate.getRate();
            }

            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(EXCHANGE_RATE_API + fromCurrency))
                    .timeout(Duration.ofSeconds(10))
                    .build();

            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

            if (response.statusCode() != 200) {
                throw new IOException("Failed to fetch exchange rates: " + response.body());
            }

            String responseBody = response.body();
            double rate = parseRateFromResponse(responseBody, toCurrency);

            cache.put(cacheKey, new CacheEntry(rate, Instant.now().plus(Duration.ofMinutes(10))));
            return rate;
        }

        private double parseRateFromResponse(String responseBody, String toCurrency) {
            // Simple JSON parsing (for simplicity; in production, use a proper JSON parser)
            int startIndex = responseBody.indexOf("\"" + toCurrency + "\":") + toCurrency.length() + 3;
            int endIndex = responseBody.indexOf(",", startIndex);
            if (endIndex == -1) {
                endIndex = responseBody.indexOf("}", startIndex);
            }
            String rateStr = responseBody.substring(startIndex, endIndex);
            return Double.parseDouble(rateStr);
        }
    }

    static class CacheEntry {
        private final double rate;
        private final Instant expiryTime;

        public CacheEntry(double rate, Instant expiryTime) {
            this.rate = rate;
            this.expiryTime = expiryTime;
        }

        public double getRate() {
            return rate;
        }

        public boolean isExpired() {
            return Instant.now().isAfter(expiryTime);
        }
    }
}
