import java.nio.file.FileSystems;

public class ServerHealthMonitor {

    private static final Map<String, Object> healthCache = new ConcurrentHashMap<>();
    private static final Duration TTL = Duration.ofMinutes(1);

    public static void main(String[] args) throws IOException {
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
        scheduler.scheduleAtFixedRate(ServerHealthMonitor::updateHealthMetrics, 0, 1, TimeUnit.MINUTES);

        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/health", exchange -> {
            if ("GET".equals(exchange.getRequestMethod())) {
                String response = getHealthSummaryJson();
                exchange.sendResponseHeaders(200, response.getBytes().length);
                OutputStream os = exchange.getResponseBody();
                os.write(response.getBytes());
                os.close();
            } else {
                exchange.sendResponseHeaders(405, -1);
            }
        });
        server.setExecutor(Executors.newCachedThreadPool());
        server.start();
    }

    private static void updateHealthMetrics() {
        OperatingSystemMXBean osBean = ManagementFactory.getOperatingSystemMXBean();
        double cpuLoad = osBean.getSystemLoadAverage();
        long memoryTotal = Runtime.getRuntime().totalMemory();
        long memoryUsed = memoryTotal - Runtime.getRuntime().freeMemory();
        long diskTotal = 0;
        long diskFree = 0;

        try {
            for (FileStore store : FileSystems.getDefault().getFileStores()) {
                diskTotal += store.getTotalSpace();
                diskFree += store.getUsableSpace();
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        healthCache.put("timestamp", Instant.now().toString());
        healthCache.put("cpuLoad", cpuLoad);
        healthCache.put("memoryUsage", Map.of(
                "used", memoryUsed,
                "total", memoryTotal,
                "percentage", (double) memoryUsed / memoryTotal * 100
        ));
        healthCache.put("diskUsage", Map.of(
                "used", diskTotal - diskFree,
                "total", diskTotal,
                "percentage", (double) (diskTotal - diskFree) / diskTotal * 100
        ));
    }

    private static String getHealthSummaryJson() {
        Instant now = Instant.now();
        Instant lastUpdated = Instant.parse(healthCache.get("timestamp").toString());
        if (Duration.between(lastUpdated, now).compareTo(TTL) > 0) {
            return "{\"error\":\"Data expired\"}";
        }
        return "{\"cpuLoad\":" + healthCache.get("cpuLoad") + "," +
               "\"memoryUsage\":" + healthCache.get("memoryUsage") + "," +
               "\"diskUsage\":" + healthCache.get("diskUsage") + "}";
    }
}
