use serde_json::{Value, Map};
use std::path::Path;
use tokio::fs;
use tokio::io::AsyncWriteExt;

#[derive(Debug)]
enum MergeError {
    IoError(std::io::Error),
    JsonError(serde_json::Error),
    SchemaMismatch(String),
}

async fn read_json_file(path: &Path) -> Result<Value, MergeError> {
    let content = fs::read_to_string(path)
        .await
        .map_err(MergeError::IoError)?;
    serde_json::from_str(&content).map_err(MergeError::JsonError)
}

async fn merge_json_files(
    input_paths: &[&Path],
    output_path: &Path,
) -> Result<(), MergeError> {
    let mut merged: Map<String, Value> = Map::new();
    let mut first_schema: Option<Value> = None;

    for path in input_paths {
        let json = read_json_file(path).await?;

        if let Some(ref schema) = first_schema {
            if !check_schema_compatibility(&json, schema) {
                return Err(MergeError::SchemaMismatch(format!(
                    "Schema mismatch in file: {}",
                    path.display()
                )));
            }
        } else {
            first_schema = Some(json.clone());
        }

        if let Some(obj) = json.as_object() {
            for (key, value) in obj {
                merged.insert(key.clone(), value.clone());
            }
        } else {
            return Err(MergeError::SchemaMismatch(
                "Expected JSON object in input files".to_string(),
            ));
        }
    }

    let merged_json = Value::Object(merged);
    let serialized = serde_json::to_string_pretty(&merged_json)
        .map_err(MergeError::JsonError)?;

    let mut file = fs::File::create(output_path)
        .await
        .map_err(MergeError::IoError)?;
    file.write_all(serialized.as_bytes())
        .await
        .map_err(MergeError::IoError)?;

    Ok(())
}

fn check_schema_compatibility(a: &Value, b: &Value) -> bool {
    match (a, b) {
        (Value::Object(a_obj), Value::Object(b_obj)) => {
            a_obj.keys().all(|k| b_obj.contains_key(k))
                && b_obj.keys().all(|k| a_obj.contains_key(k))
        }
        (Value::Array(a_arr), Value::Array(b_arr)) => {
            a_arr.len() == b_arr.len()
                && a_arr
                    .iter()
                    .zip(b_arr.iter())
                    .all(|(a, b)| check_schema_compatibility(a, b))
        }
        _ => a == b,
    }
}

#[tokio::main]
async fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("Usage: {} <output_file> <input_file1> [<input_file2> ...]", args[0]);
        std::process::exit(1);
    }

    let output_path = Path::new(&args[1]);
    let input_paths: Vec<&Path> = args[2..].iter().map(|s| Path::new(s)).collect();

    match merge_json_files(&input_paths, output_path).await {
        Ok(_) => println!("Successfully merged JSON files to {}", output_path.display()),
        Err(e) => {
            eprintln!("Error: {:?}", e);
            std::process::exit(1);
        }
    }
}
