import json
import logging
import requests
from datetime import datetime
import sqlite3
from typing import Dict, List, Optional

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def fetch_data(api_url: str) -> Optional[List[Dict]]:
    try:
        if response := requests.get(api_url):
            return response.json()
        logger.error(f"Failed to fetch data: HTTP {response.status_code}")
    except requests.RequestException as e:
        logger.error(f"Request failed: {e}")
    return None

def normalize_data(raw_data: List[Dict]) -> List[Dict]:
    normalized = []
    for record in raw_data:
        try:
            # Convert date to ISO 8601 if present
            if 'date' in record:
                record['date'] = datetime.strptime(record['date'], '%Y-%m-%d').isoformat()
            normalized.append(record)
        except (ValueError, KeyError) as e:
            logger.warning(f"Data inconsistency in record: {record}. Error: {e}")
    return normalized

def load_to_database(data: List[Dict], db_path: str) -> None:
    try:
        with sqlite3.connect(db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS processed_data (
                    id INTEGER PRIMARY KEY,
                    date TEXT,
                    -- Add other fields as needed
                    raw_json TEXT
                )
            ''')
            for record in data:
                cursor.execute('''
                    INSERT INTO processed_data (date, raw_json)
                    VALUES (?, ?)
                ''', (record.get('date'), json.dumps(record)))
            conn.commit()
            logger.info(f"Processed {len(data)} records")
    except sqlite3.Error as e:
        logger.error(f"Database error: {e}")

def main():
    API_URL = "https://api.example.com/data"
    DB_PATH = "processed_data.db"

    if raw_data := fetch_data(API_URL):
        normalized_data = normalize_data(raw_data)
        load_to_database(normalized_data, DB_PATH)

if __name__ == "__main__":
    main()
