import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.UUID;
import java.util.Base64;
import java.io.IOException;
import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;
import java.net.InetSocketAddress;
import java.util.Map;

public class URLShortenerService {

    private static final ConcurrentHashMap<String, URLRecord> urlDatabase = new ConcurrentHashMap<>();
    private static final HttpClient httpClient = HttpClient.newHttpClient();
    private static final String API_KEY = "SECURE_API_KEY"; // Replace with secure key management

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/shorten", new ShortenHandler());
        server.createContext("/", new RedirectHandler());
        server.setExecutor(null);
        server.start();
        System.out.println("URL Shortener Service running on port 8080");
    }

    static class URLRecord {
        String originalUrl;
        AtomicLong accessCount = new AtomicLong(0);

        URLRecord(String originalUrl) {
            this.originalUrl = originalUrl;
        }
    }

    static class ShortenHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equals(exchange.getRequestMethod())) {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
                return;
            }

            String apiKey = exchange.getRequestHeaders().getFirst("X-API-KEY");
            if (apiKey == null || !apiKey.equals(API_KEY)) {
                exchange.sendResponseHeaders(401, -1); // Unauthorized
                return;
            }

            String originalUrl = new String(exchange.getRequestBody().readAllBytes());
            String shortCode = generateShortCode();
            urlDatabase.put(shortCode, new URLRecord(originalUrl));

            String response = "http://localhost:8080/" + shortCode;
            exchange.sendResponseHeaders(200, response.length());
            exchange.getResponseBody().write(response.getBytes());
            exchange.close();
        }

        private String generateShortCode() {
            return Base64.getUrlEncoder().encodeToString(UUID.randomUUID().toString().getBytes()).substring(0, 8);
        }
    }

    static class RedirectHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            String shortCode = exchange.getRequestURI().getPath().substring(1);
            URLRecord record = urlDatabase.get(shortCode);

            if (record == null) {
                exchange.sendResponseHeaders(404, -1); // Not Found
                return;
            }

            record.accessCount.incrementAndGet();
            exchange.getResponseHeaders().set("Location", record.originalUrl);
            exchange.sendResponseHeaders(302, -1); // Redirect
            exchange.close();

            // Asynchronous tracking
            CompletableFuture.runAsync(() -> {
                HttpRequest trackingRequest = HttpRequest.newBuilder()
                    .uri(URI.create("http://localhost:8080/track"))
                    .header("Content-Type", "application/json")
                    .POST(HttpRequest.BodyPublishers.ofString(
                        String.format("{\"shortCode\":\"%s\",\"accessCount\":%d}", shortCode, record.accessCount.get())))
                    .build();
                httpClient.sendAsync(trackingRequest, HttpResponse.BodyHandlers.discarding());
            });
        }
    }
}
