use std::path::PathBuf;
use hashbrown::hash_map::DefaultHashBuilder;
use tokio::fs::{self, File};
use tokio::io::AsyncWriteExt;
use serde_json::Value;
use reqwest::Client;
use std::hash::{Hash, Hasher};

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <json_file>", args[0]);
        std::process::exit(1);
    }

    let json_path = &args[1];
    let json_data = fs::read_to_string(json_path).await?;
    let urls: Vec<String> = serde_json::from_str(&json_data)?;

    let client = Client::new();
    let mut tasks = Vec::new();

    for url in urls {
        tasks.push(tokio::spawn(fetch_and_save(url, client.clone())));
    }

    for task in tasks {
        task.await??;
    }

    Ok(())
}

async fn fetch_and_save(url: String, client: Client) -> Result<(), Box<dyn std::error::Error>> {
    let response = client.get(&url).send().await?.text().await?;

    let mut hasher = DefaultHashBuilder::default().build_hasher();
    url.hash(&mut hasher);
    let hash = hasher.finish();
    let filename = format!("{:x}.txt", hash);
    let mut path = PathBuf::new();
    path.push(filename);

    let mut file = File::create(&path).await?;
    file.write_all(response.as_bytes()).await?;

    Ok(())
}
