import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class AnalyticsDaemon {
    private final Path logFilePath;
    private final String blacklistServiceUrl;
    private final Map<String, Integer> ipThreatScores = new HashMap<>();
    private final HttpClient httpClient = HttpClient.newHttpClient();
    private final Pattern ipPattern = Pattern.compile("\\b(?:\\d{1,3}\\.){3}\\d{1,3}\\b");

    public AnalyticsDaemon(String logFilePath, String blacklistServiceUrl) {
        this.logFilePath = Paths.get(logFilePath);
        this.blacklistServiceUrl = blacklistServiceUrl;
    }

    public void start() throws IOException {
        if (!Files.exists(logFilePath)) {
            throw new IOException("Log file does not exist: " + logFilePath);
        }

        ScheduledExecutorService executor = Executors.newSingleThreadScheduledExecutor();
        executor.scheduleAtFixedRate(this::processLogs, 0, 1, TimeUnit.SECONDS);
    }

    private void processLogs() {
        try (BufferedReader reader = new BufferedReader(new FileReader(logFilePath.toFile()))) {
            String line;
            while ((line = reader.readLine()) != null) {
                Matcher matcher = ipPattern.matcher(line);
                while (matcher.find()) {
                    String ip = matcher.group();
                    checkBlacklistAndUpdateScore(ip);
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading log file: " + e.getMessage());
        }
    }

    private void checkBlacklistAndUpdateScore(String ip) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(blacklistServiceUrl + "/check?ip=" + ip))
                .GET()
                .build();

        try {
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200 && "true".equalsIgnoreCase(response.body())) {
                ipThreatScores.merge(ip, 1, Integer::sum);
                System.out.println("Updated threat score for IP " + ip + ": " + ipThreatScores.get(ip));
            }
        } catch (IOException | InterruptedException e) {
            System.err.println("Error fetching blacklist data for IP " + ip + ": " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AnalyticsDaemon <logFilePath> <blacklistServiceUrl>");
            System.exit(1);
        }

        try {
            AnalyticsDaemon daemon = new AnalyticsDaemon(args[0], args[1]);
            daemon.start();
        } catch (IOException e) {
            System.err.println("Failed to start daemon: " + e.getMessage());
            System.exit(1);
        }
    }
}
