public sealed interface Media permits Book, Journal, Magazine {
    String getId();
    String getTitle();
}

final class Book implements Media {
    private final String id;
    private final String title;
    private final String author;

    public Book(String id, String title, String author) {
        this.id = id;
        this.title = title;
        this.author = author;
    }

    @Override public String getId() { return id; }
    @Override public String getTitle() { return title; }
    public String getAuthor() { return author; }
}

final class Journal implements Media {
    private final String id;
    private final String title;
    private final String publisher;

    public Journal(String id, String title, String publisher) {
        this.id = id;
        this.title = title;
        this.publisher = publisher;
    }

    @Override public String getId() { return id; }
    @Override public String getTitle() { return title; }
    public String getPublisher() { return publisher; }
}

final class Magazine implements Media {
    private final String id;
    private final String title;
    private final int issue;

    public Magazine(String id, String title, int issue) {
        this.id = id;
        this.title = title;
        this.issue = issue;
    }

    @Override public String getId() { return id; }
    @Override public String getTitle() { return title; }
    public int getIssue() { return issue; }
}

@Path("/media")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
class MediaResource {
    private final ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();
    private final HttpClient httpClient = HttpClient.newHttpClient();
    private final String dbUrl = "jdbc:postgresql://localhost:5432/library";

    @POST
    public CompletableFuture<Response> createMedia(Media media) {
        return CompletableFuture.supplyAsync(() -> {
            try (Connection conn = DriverManager.getConnection(dbUrl, "user", "password")) {
                conn.setAutoCommit(false);
                String sql = "INSERT INTO media (id, title, type, details) VALUES (?, ?, ?, ?)";
                try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                    stmt.setString(1, media.getId());
                    stmt.setString(2, media.getTitle());
                    if (media instanceof Book book) {
                        stmt.setString(3, "BOOK");
                        stmt.setString(4, "{\"author\":\"" + book.getAuthor() + "\"}");
                    } else if (media instanceof Journal journal) {
                        stmt.setString(3, "JOURNAL");
                        stmt.setString(4, "{\"publisher\":\"" + journal.getPublisher() + "\"}");
                    } else if (media instanceof Magazine magazine) {
                        stmt.setString(3, "MAGAZINE");
                        stmt.setString(4, "{\"issue\":" + magazine.getIssue() + "}");
                    }
                    stmt.executeUpdate();
                    conn.commit();
                    return Response.status(Response.Status.CREATED).entity(media).build();
                } catch (SQLException e) {
                    conn.rollback();
                    throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
                }
            } catch (SQLException e) {
                throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
            }
        }, executor);
    }

    @GET
    @Path("/{id}")
    public CompletableFuture<Response> getMedia(@PathParam("id") String id) {
        return CompletableFuture.supplyAsync(() -> {
            try (Connection conn = DriverManager.getConnection(dbUrl, "user", "password")) {
                String sql = "SELECT * FROM media WHERE id = ?";
                try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                    stmt.setString(1, id);
                    ResultSet rs = stmt.executeQuery();
                    if (rs.next()) {
                        String type = rs.getString("type");
                        String title = rs.getString("title");
                        String details = rs.getString("details");
                        Media media = switch (type) {
                            case "BOOK" -> new Book(id, title, details.split("\"")[3]);
                            case "JOURNAL" -> new Journal(id, title, details.split("\"")[3]);
                            case "MAGAZINE" -> new Magazine(id, title, Integer.parseInt(details.split(":")[1].replaceAll("[^0-9]", "")));
                            default -> throw new IllegalArgumentException("Unknown media type");
                        };
                        return Response.ok(media).build();
                    } else {
                        return Response.status(Response.Status.NOT_FOUND).build();
                    }
                }
            } catch (SQLException e) {
                throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
            }
        }, executor);
    }

    @PUT
    @Path("/{id}")
    public CompletableFuture<Response> updateMedia(@PathParam("id") String id, Media media) {
        return CompletableFuture.supplyAsync(() -> {
            try (Connection conn = DriverManager.getConnection(dbUrl, "user", "password")) {
                conn.setAutoCommit(false);
                String sql = "UPDATE media SET title = ?, details = ? WHERE id = ?";
                try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                    stmt.setString(1, media.getTitle());
                    if (media instanceof Book book) {
                        stmt.setString(2, "{\"author\":\"" + book.getAuthor() + "\"}");
                    } else if (media instanceof Journal journal) {
                        stmt.setString(2, "{\"publisher\":\"" + journal.getPublisher() + "\"}");
                    } else if (media instanceof Magazine magazine) {
                        stmt.setString(2, "{\"issue\":" + magazine.getIssue() + "}");
                    }
                    stmt.setString(3, id);
                    int updated = stmt.executeUpdate();
                    conn.commit();
                    return updated > 0 ? Response.ok(media).build() : Response.status(Response.Status.NOT_FOUND).build();
                } catch (SQLException e) {
                    conn.rollback();
                    throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
                }
            } catch (SQLException e) {
                throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
            }
        }, executor);
    }

    @DELETE
    @Path("/{id}")
    public CompletableFuture<Response> deleteMedia(@PathParam("id") String id) {
        return CompletableFuture.supplyAsync(() -> {
            try (Connection conn = DriverManager.getConnection(dbUrl, "user", "password")) {
                conn.setAutoCommit(false);
                String sql = "DELETE FROM media WHERE id = ?";
                try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                    stmt.setString(1, id);
                    int deleted = stmt.executeUpdate();
                    conn.commit();
                    return deleted > 0 ? Response.noContent().build() : Response.status(Response.Status.NOT_FOUND).build();
                } catch (SQLException e) {
                    conn.rollback();
                    throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
                }
            } catch (SQLException e) {
                throw new WebApplicationException(e, Response.Status.INTERNAL_SERVER_ERROR);
            }
        }, executor);
    }

    @GET
    @Path("/external")
    public CompletableFuture<Response> fetchExternalData() {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create("https://api.example.com/external-media"))
                .build();
        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApplyAsync(response -> Response.ok(response.body()).build(), executor);
    }
}

