use std::path::Path;
use std::time::SystemTime;
use std::fs::{File, OpenOptions};
use std::io::{Write, Read};
use sha2::{Sha256, Digest};
use tokio::fs;
use tokio::time;
use notify::{RecommendedWatcher, RecursiveMode, Watcher, Config};
use notify::event::{Event, EventKind};
use chrono::{DateTime, Local};

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <directory>", args[0]);
        std::process::exit(1);
    }
    let dir_path = &args[1];

    let (tx, mut rx) = tokio::sync::mpsc::channel(1);

    let mut watcher = RecommendedWatcher::new(
        move |res| {
            if let Ok(event) = res {
                let _ = tx.blocking_send(event);
            }
        },
        Config::default(),
    )?;

    watcher.watch(Path::new(dir_path), RecursiveMode::Recursive)?;

    let log_file = OpenOptions::new()
        .create(true)
        .append(true)
        .open("file_changes.log")?;

    while let Some(event) = rx.recv().await {
        if let EventKind::Modify(_) | EventKind::Create(_) = event.kind {
            for path in event.paths {
                if path.is_file() {
                    tokio::spawn(process_file(path, log_file.try_clone()?));
                }
            }
        }
    }

    Ok(())
}

async fn process_file(path: std::path::PathBuf, mut log_file: File) -> Result<(), Box<dyn std::error::Error>> {
    let metadata = fs::metadata(&path).await?;
    let modified_time = metadata.modified()?;
    let datetime: DateTime<Local> = modified_time.into();
    let timestamp = datetime.format("%Y-%m-%d %H:%M:%S").to_string();

    let mut file = File::open(&path)?;
    let mut contents = Vec::new();
    file.read_to_end(&mut contents)?;

    let mut hasher = Sha256::new();
    hasher.update(&contents);
    let hash = format!("{:x}", hasher.finalize());

    let file_name = path.file_name().unwrap().to_string_lossy().into_owned();

    writeln!(
        log_file,
        "File: {}, Modified: {}, Hash: {}",
        file_name, timestamp, hash
    )?;

    Ok(())
}
