from pymongo import MongoClient
from pymongo.encryption_options import AutoEncryptionOpts
from pymongo.errors import PyMongoError
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler
from typing import Dict, Any
import base64
from cryptography.fernet import Fernet

# Configuration
WATCH_DIR = "/path/to/watch"  # Specify the directory to monitor
MONGO_URI = "mongodb://localhost:27017"  # MongoDB connection URI
DB_NAME = "json_monitor_db"  # Database name
COLLECTION_NAME = "json_data"  # Collection name
LOG_FILE = "json_monitor.log"  # Log file path
ENCRYPTION_KEY = Fernet.generate_key()  # Generate a new encryption key (store securely in production)

# Setup logging
logging.basicConfig(
    filename=LOG_FILE,
    level=logging.INFO,
    format="%(asctime)s - %(levelname)s - %(message)s"
)

# MongoDB encryption setup
key_bytes = base64.b64encode(ENCRYPTION_KEY)
kms_providers = {"local": {"key": key_bytes}}
schema = {
    "json.bson": {
        "bsonType": "object",
        "encryptMetadata": {"keyId": "/_id"},
        "properties": {
            "data": {
                "encrypt": {
                    "bsonType": "object",
                    "algorithm": "AEAD_AES_256_CBC_HMAC_SHA_512-Deterministic"
                }
            }
        }
    }
}

auto_encryption_opts = AutoEncryptionOpts(
    kms_providers=kms_providers,
    schema_map={f"{DB_NAME}.{COLLECTION_NAME}": schema}
)

# MongoDB client
client = MongoClient(MONGO_URI, auto_encryption_opts=auto_encryption_opts)
db = client[DB_NAME]
collection = db[COLLECTION_NAME]

# File handler
class JSONHandler(FileSystemEventHandler):
    def on_modified(self, event):
        if not event.is_directory and event.src_path.endswith('.json'):
            self.process_json(event.src_path)

    def on_created(self, event):
        if not event.is_directory and event.src_path.endswith('.json'):
            self.process_json(event.src_path)

    def process_json(self, file_path: str):
        try:
            with open(file_path, 'r') as f:
                data = json.load(f)

            # Pattern matching for validation and decomposition
            match data:
                case {"metadata": {"id": str(id), "timestamp": str(timestamp)}, **rest}:
                    document = {
                        "_id": id,
                        "timestamp": timestamp,
                        "data": rest
                    }
                case {"id": str(id), **rest}:
                    document = {
                        "_id": id,
                        "data": rest
                    }
                case _:
                    raise ValueError("Unsupported JSON structure")

            # Update MongoDB
            collection.update_one(
                {"_id": document["_id"]},
                {"$set": document},
                upsert=True
            )
            logging.info(f"Processed and updated {file_path}")

        except json.JSONDecodeError as e:
            logging.error(f"Invalid JSON in {file_path}: {e}")
        except ValueError as e:
            logging.error(f"Validation error in {file_path}: {e}")
        except PyMongoError as e:
            logging.error(f"MongoDB error processing {file_path}: {e}")
        except Exception as e:
            logging.error(f"Unexpected error processing {file_path}: {e}")

# Main execution
if __name__ == "__main__":
    if not os.path.exists(WATCH_DIR):
        os.makedirs(WATCH_DIR)
        logging.info(f"Created watch directory: {WATCH_DIR}")

    event_handler = JSONHandler()
    observer = Observer()
    observer.schedule(event_handler, WATCH_DIR, recursive=True)
    observer.start()
    logging.info(f"Started monitoring {WATCH_DIR}")

    try:
        while True:
            pass
    except KeyboardInterrupt:
        observer.stop()
    observer.join()
