public class WeatherApp {
    private static final Logger LOGGER = Logger.getLogger(WeatherApp.class.getName());
    private static final String WEATHER_API_URL = "https://api.openweathermap.org/data/2.5/weather?q=%s&appid=YOUR_API_KEY&units=metric";
    private static final HttpClient httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_3)
            .connectTimeout(Duration.ofSeconds(10))
            .build();
    private static final ObjectMapper objectMapper = new ObjectMapper();
    private static final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public static void main(String[] args) {
        List<String> cities = List.of("London", "New York", "Tokyo", "Paris", "Berlin");
        int updateIntervalMinutes = 5;

        scheduler.scheduleAtFixedRate(() -> {
            for (String city : cities) {
                fetchWeatherData(city);
            }
        }, 0, updateIntervalMinutes, TimeUnit.MINUTES);
    }

    private static void fetchWeatherData(String city) {
        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(String.format(WEATHER_API_URL, city)))
                    .timeout(Duration.ofSeconds(10))
                    .build();

            httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                    .thenApply(HttpResponse::body)
                    .thenAccept(json -> parseAndDisplayWeather(json, city))
                    .exceptionally(ex -> {
                        LOGGER.log(Level.SEVERE, "Error fetching weather data for " + city, ex);
                        return null;
                    });
        } catch (Exception ex) {
            LOGGER.log(Level.SEVERE, "Error creating request for " + city, ex);
        }
    }

    private static void parseAndDisplayWeather(String json, String city) {
        try {
            JsonNode root = objectMapper.readTree(json);
            if (root.has("cod") && root.get("cod").asInt() != 200) {
                LOGGER.log(Level.WARNING, "Invalid city or API error for " + city + ": " + root.get("message").asText());
                return;
            }

            double temp = root.path("main").path("temp").asDouble();
            double windSpeed = root.path("wind").path("speed").asDouble();
            double precipitation = root.path("rain") != null ? root.path("rain").path("1h").asDouble(0) : 0;

            System.out.printf("Weather in %s: Temperature=%.1f°C, Wind Speed=%.1fm/s, Precipitation=%.1fmm%n",
                    city, temp, windSpeed, precipitation);
        } catch (Exception ex) {
            LOGGER.log(Level.SEVERE, "Error parsing weather data for " + city, ex);
        }
    }
}
