import java.net.URL;
import java.net.HttpURLConnection;
import java.io.InputStream;
import java.time.Instant;
import java.sql.*;
import java.util.concurrent.*;
import java.util.List;
import java.util.ArrayList;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

public sealed interface RSSFeedItem permits NewsItem {
    String title();
    Instant pubDate();
}

final record NewsItem(String title, Instant pubDate) implements RSSFeedItem {}

public class RSSProcessor {
    private static final String DB_URL = "jdbc:sqlite:news.db";
    private static final String CREATE_TABLE_SQL = """
        CREATE TABLE IF NOT EXISTS news (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            pub_date TEXT NOT NULL
        )
    """;

    public static void main(String[] args) {
        List<String> feedUrls = List.of(
            "https://example.com/feed1.rss",
            "https://example.com/feed2.rss"
        );

        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            initializeDatabase(conn);
            processFeeds(feedUrls, conn);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void initializeDatabase(Connection conn) throws SQLException {
        try (Statement stmt = conn.createStatement()) {
            stmt.execute(CREATE_TABLE_SQL);
        }
    }

    private static void processFeeds(List<String> feedUrls, Connection conn) {
        try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
            List<Future<List<RSSFeedItem>>> futures = feedUrls.stream()
                .map(url -> scope.fork(() -> fetchAndParseFeed(url)))
                .toList();

            scope.join();
            scope.throwIfFailed();

            futures.forEach(future -> {
                try {
                    storeItems(conn, future.get());
                } catch (Exception e) {
                    e.printStackTrace();
                }
            });
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static List<RSSFeedItem> fetchAndParseFeed(String feedUrl) throws Exception {
        URL url = new URL(feedUrl);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod("GET");

        try (InputStream input = conn.getInputStream()) {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document doc = builder.parse(input);
            return parseItems(doc);
        } finally {
            conn.disconnect();
        }
    }

    private static List<RSSFeedItem> parseItems(Document doc) {
        List<RSSFeedItem> items = new ArrayList<>();
        NodeList itemNodes = doc.getElementsByTagName("item");

        for (int i = 0; i < itemNodes.getLength(); i++) {
            Element item = (Element) itemNodes.item(i);
            String title = item.getElementsByTagName("title").item(0).getTextContent();
            String pubDateStr = item.getElementsByTagName("pubDate").item(0).getTextContent();
            Instant pubDate = Instant.parse(pubDateStr);
            items.add(new NewsItem(title, pubDate));
        }

        return items;
    }

    private static void storeItems(Connection conn, List<RSSFeedItem> items) throws SQLException {
        String sql = "INSERT INTO news (title, pub_date) VALUES (?, ?)";

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            for (RSSFeedItem item : items) {
                switch (item) {
                    case NewsItem newsItem -> {
                        stmt.setString(1, newsItem.title());
                        stmt.setString(2, newsItem.pubDate().toString());
                        stmt.executeUpdate();
                    }
                }
            }
        }
    }
}
