use std::fs;
use std::path::Path;

pub const MIGRATIONS: EmbeddedMigrations = embed_migrations!("migrations");

#[derive(Debug)]
struct Migration {
    version: i64,
    name: String,
    applied_at: chrono::NaiveDateTime,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let database_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let migrations_dir = env::var("MIGRATIONS_DIR").unwrap_or_else(|_| "migrations".to_string());

    task::block_on(async {
        let mut conn = PgConnection::establish(&database_url)?;

        // Create migrations table if not exists
        conn.run_pending_migrations(MIGRATIONS).map_err(|e| {
            eprintln!("Failed to run migrations: {}", e);
            e
        })?;

        let migration_files = fs::read_dir(&migrations_dir)?
            .filter_map(|entry| {
                let entry = entry.ok()?;
                let path = entry.path();
                if path.is_file() && path.extension().map_or(false, |ext| ext == "sql") {
                    Some(path)
                } else {
                    None
                }
            })
            .collect::<Vec<_>>();

        for file in migration_files {
            let migration_name = file.file_stem().unwrap().to_string_lossy().into_owned();
            let migration_sql = fs::read_to_string(&file)?;

            let result = conn.transaction::<_, diesel::result::Error, _>(|conn| {
                conn.batch_execute(&migration_sql)?;
                diesel::insert_into(migrations::table)
                    .values((
                        migrations::version.eq(migration_name.split('_').next().unwrap().parse::<i64>()?),
                        migrations::name.eq(&migration_name),
                        migrations::applied_at.eq(chrono::Local::now().naive_local()),
                    ))
                    .execute(conn)?;
                Ok(())
            });

            match result {
                Ok(_) => println!("Applied migration: {}", migration_name),
                Err(e) => {
                    eprintln!("Failed to apply migration {}: {}", migration_name, e);
                    return Err(e.into());
                }
            }
        }

        Ok(())
    })
}

