import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.HashMap;
import java.util.Map;
import com.google.gson.Gson;

public class ConfigFileMonitor {
    private final WatchService watchService;
    private final Map<WatchKey, Path> keys;
    private final Gson gson;
    private final Path logFile;

    public ConfigFileMonitor(Path logFile) throws IOException {
        this.watchService = FileSystems.getDefault().newWatchService();
        this.keys = new HashMap<>();
        this.gson = new Gson();
        this.logFile = logFile;
    }

    public void registerDirectory(Path dir) throws IOException {
        WatchKey key = dir.register(watchService,
                StandardWatchEventKinds.ENTRY_CREATE,
                StandardWatchEventKinds.ENTRY_DELETE,
                StandardWatchEventKinds.ENTRY_MODIFY);
        keys.put(key, dir);
    }

    public void processEvents() throws IOException {
        WatchKey key;
        while ((key = watchService.take()) != null) {
            for (WatchEvent<?> event : key.pollEvents()) {
                Path dir = keys.get(key);
                Path file = dir.resolve((Path) event.context());
                logEvent(event.kind(), file);
            }
            key.reset();
        }
    }

    private void logEvent(WatchEvent.Kind<?> kind, Path file) throws IOException {
        Map<String, String> logEntry = new HashMap<>();
        logEntry.put("timestamp", LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME));
        logEntry.put("eventType", kind.name());
        logEntry.put("file", file.toString());

        String jsonLog = gson.toJson(logEntry) + System.lineSeparator();
        Files.write(logFile, jsonLog.getBytes(), StandardOpenOption.CREATE, StandardOpenOption.APPEND);
    }

    public static void main(String[] args) throws IOException {
        if (args.length < 2) {
            System.err.println("Usage: java ConfigFileMonitor <logFilePath> <dirToWatch1> [dirToWatch2...]");
            System.exit(1);
        }

        Path logFile = Paths.get(args[0]);
        ConfigFileMonitor monitor = new ConfigFileMonitor(logFile);

        for (int i = 1; i < args.length; i++) {
            Path dir = Paths.get(args[i]);
            if (Files.isDirectory(dir)) {
                monitor.registerDirectory(dir);
            } else {
                System.err.println("Not a directory: " + dir);
            }
        }

        monitor.processEvents();
    }
}
