public class ServerHealthMonitor {
    private static final Logger LOGGER = Logger.getLogger(ServerHealthMonitor.class.getName());
    private static final String CONFIG_FILE = "config.properties";
    private static final HttpClient httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(10))
            .build();

    public static void main(String[] args) {
        try {
            Properties config = new Properties();
            config.load(Files.newInputStream(Path.of(CONFIG_FILE)));
            long interval = Long.parseLong(config.getProperty("interval", "60"));
            List<String> urls = List.of(config.getProperty("urls", "").split(","));

            ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
            scheduler.scheduleAtFixedRate(() -> monitorServers(urls), 0, interval, TimeUnit.SECONDS);
        } catch (Exception e) {
            LOGGER.severe("Failed to start monitor: " + e.getMessage());
        }
    }

    private static void monitorServers(List<String> urls) {
        urls.forEach(url -> {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(url))
                    .timeout(Duration.ofSeconds(5))
                    .build();

            CompletableFuture<HttpResponse<String>> responseFuture = httpClient
                    .sendAsync(request, HttpResponse.BodyHandlers.ofString());

            responseFuture.thenAccept(response -> {
                if (response.statusCode() >= 200 && response.statusCode() < 300) {
                    LOGGER.info("Server " + url + " is healthy. Status: " + response.statusCode());
                } else {
                    LOGGER.warning("Server " + url + " returned error status: " + response.statusCode());
                }
            }).exceptionally(ex -> {
                LOGGER.severe("Server " + url + " is not responding: " + ex.getMessage());
                return null;
            });
        });
    }
