                Err(e) => eprintln!("Error processing URL: {}", e),
            }
        });
    }

    // Wait for all tasks to complete
    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;

    let map = results.lock().await;
    println!("{:?}", *map);
}

