use std::error::Error;
use std::fmt;
use log::{info, error, debug};

#[derive(Debug, Serialize, Deserialize)]
struct CustomData {
    // Define your custom fields here
    field1: String,
    field2: i32,
}

#[derive(Debug)]
enum AppError {
    JsonError(serde_json::Error),
    IoError(std::io::Error),
    CustomError(String),
}

impl fmt::Display for AppError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            AppError::JsonError(e) => write!(f, "JSON error: {}", e),
            AppError::IoError(e) => write!(f, "IO error: {}", e),
            AppError::CustomError(e) => write!(f, "Custom error: {}", e),
        }
    }
}

impl Error for AppError {}

impl From<serde_json::Error> for AppError {
    fn from(err: serde_json::Error) -> AppError {
        AppError::JsonError(err)
    }
}

impl From<std::io::Error> for AppError {
    fn from(err: std::io::Error) -> AppError {
        AppError::IoError(err)
    }
}

async fn handle_client(mut stream: TcpStream) -> Result<(), AppError> {
    let mut buffer = Vec::new();
    stream.read_to_end(&mut buffer).await?;

    let json_str = String::from_utf8(buffer).map_err(|e| AppError::CustomError(e.to_string()))?;
    debug!("Received JSON payload: {}", json_str);

    let data: CustomData = serde_json::from_str(&json_str)?;
    debug!("Deserialized data: {:?}", data);

    // Apply custom business logic here
    let transformed_data = transform_data(data)?;

    let response_json = serde_json::to_string(&transformed_data)?;
    debug!("Transformed data: {}", response_json);

    stream.write_all(response_json.as_bytes()).await?;
    stream.flush().await?;

    Ok(())
}

fn transform_data(data: CustomData) -> Result<CustomData, AppError> {
    // Implement your custom transformation logic here
    Ok(CustomData {
        field1: data.field1.to_uppercase(),
        field2: data.field2 * 2,
    })
}

#[async_std::main]
async fn main() -> Result<(), Box<dyn Error>> {
    env_logger::init();

    let port = 8080; // Specify your port here
    let listener = TcpListener::bind(format!("127.0.0.1:{}", port)).await?;
    info!("Server listening on port {}", port);

    let mut incoming = listener.incoming();

    while let Some(stream) = incoming.next().await {
        match stream {
            Ok(stream) => {
                info!("New connection: {}", stream.peer_addr()?);
                task::spawn(async move {
                    if let Err(e) = handle_client(stream).await {
                        error!("Error handling client: {}", e);
                    }
                });
            }
            Err(e) => {
                error!("Connection failed: {}", e);
            }
        }
    }

    Ok(())
}
