import java.util.Properties;
import java.time.Instant;
import java.util.concurrent.CountDownLatch;
import org.apache.kafka.clients.consumer.*;
import org.apache.kafka.common.serialization.StringDeserializer;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.sql.*;
import javax.sql.DataSource;
import org.postgresql.ds.PGSimpleDataSource;

public class ECommerceTransactionService {

    private static final String KAFKA_TOPIC = "ecommerce-transactions";
    private static final String DB_URL = "jdbc:postgresql://localhost:5432/ecommerce";
    private static final String DB_USER = "postgres";
    private static final String DB_PASSWORD = "postgres";

    public static void main(String[] args) {
        new ECommerceTransactionService().run();
    }

    public void run() {
        CountDownLatch latch = new CountDownLatch(1);
        try (KafkaConsumer<String, String> consumer = createKafkaConsumer()) {
            consumer.subscribe(List.of(KAFKA_TOPIC));
            DataSource dataSource = createDataSource();
            ObjectMapper objectMapper = new ObjectMapper();

            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(java.time.Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    try {
                        Transaction transaction = objectMapper.readValue(record.value(), Transaction.class);
                        if (validateTransaction(transaction)) {
                            persistTransaction(transaction, dataSource);
                        }
                    } catch (Exception e) {
                        System.err.println("Error processing transaction: " + e.getMessage());
                        // Implement rollback logic if needed
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("Error in consumer: " + e.getMessage());
        } finally {
            latch.countDown();
        }
    }

    private KafkaConsumer<String, String> createKafkaConsumer() {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "ecommerce-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        return new KafkaConsumer<>(props);
    }

    private DataSource createDataSource() {
        PGSimpleDataSource dataSource = new PGSimpleDataSource();
        dataSource.setUrl(DB_URL);
        dataSource.setUser(DB_USER);
        dataSource.setPassword(DB_PASSWORD);
        return dataSource;
    }

    private boolean validateTransaction(Transaction transaction) {
        if (transaction instanceof PaymentTransaction payment) {
            return payment.amount() > 0 && !payment.paymentMethod().isEmpty();
        } else if (transaction instanceof RefundTransaction refund) {
            return refund.amount() > 0 && refund.originalTransactionId() != null;
        }
        return false;
    }

    private void persistTransaction(Transaction transaction, DataSource dataSource) throws SQLException {
        Connection conn = dataSource.getConnection();
        try {
            conn.setAutoCommit(false);
            if (transaction instanceof PaymentTransaction payment) {
                persistPayment(payment, conn);
            } else if (transaction instanceof RefundTransaction refund) {
                persistRefund(refund, conn);
            }
            conn.commit();
        } catch (SQLException e) {
            conn.rollback();
            throw e;
        } finally {
            conn.close();
        }
    }

    private void persistPayment(PaymentTransaction payment, Connection conn) throws SQLException {
        String sql = "INSERT INTO payments (id, amount, payment_method, timestamp) VALUES (?, ?, ?, ?)";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, payment.id());
            stmt.setDouble(2, payment.amount());
            stmt.setString(3, payment.paymentMethod());
            stmt.setTimestamp(4, Timestamp.from(Instant.now()));
            stmt.executeUpdate();
        }
    }

    private void persistRefund(RefundTransaction refund, Connection conn) throws SQLException {
        String sql = "INSERT INTO refunds (id, amount, original_transaction_id, timestamp) VALUES (?, ?, ?, ?)";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, refund.id());
            stmt.setDouble(2, refund.amount());
            stmt.setString(3, refund.originalTransactionId());
            stmt.setTimestamp(4, Timestamp.from(Instant.now()));
            stmt.executeUpdate();
        }
    }
}

sealed interface Transaction permits PaymentTransaction, RefundTransaction {
    String id();
}

record PaymentTransaction(String id, double amount, String paymentMethod) implements Transaction {}
record RefundTransaction(String id, double amount, String originalTransactionId) implements Transaction {}
