use std::path::Path;
use std::sync::Arc;
use tokio::fs;
use tokio::sync::mpsc;
use tokio::task;
use aws_sdk_s3 as s3;
use aws_sdk_s3::types::ByteStream;
use log::{error, info};
use notify::{RecommendedWatcher, RecursiveMode, Watcher};
use notify::event::CreateKind;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();

    let config = aws_config::load_from_env().await;
    let s3_client = Arc::new(s3::Client::new(&config));
    let bucket_name = "your-bucket-name"; // Replace with your bucket name
    let watch_dir = "./watch_dir"; // Replace with your directory path

    let (tx, mut rx) = mpsc::channel(100);

    // Spawn watcher in a blocking task
    let watch_handle = task::spawn_blocking(move || {
        let mut watcher: RecommendedWatcher = Watcher::new_immediate(move |res| {
            if let Ok(event) = res {
                if let CreateKind::File = event.kind {
                    if let Some(path) = event.paths.first() {
                        if let Err(e) = tx.blocking_send(path.clone()) {
                            error!("Failed to send file path: {}", e);
                        }
                    }
                }
            }
        })?;

        watcher.watch(Path::new(watch_dir), RecursiveMode::NonRecursive)?;
        std::thread::park();
        Ok::<(), notify::Error>(())
    });

    // Process file uploads
    while let Some(file_path) = rx.recv().await {
        let s3_client = s3_client.clone();
        let bucket_name = bucket_name.to_string();

        task::spawn(async move {
            match upload_file(&s3_client, &bucket_name, &file_path).await {
                Ok(_) => info!("Successfully uploaded: {}", file_path.display()),
                Err(e) => error!("Failed to upload {}: {}", file_path.display(), e),
            }
        });
    }

    watch_handle.abort();
    Ok(())
}

async fn upload_file(
    client: &s3::Client,
    bucket: &str,
    file_path: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    let body = ByteStream::from_path(file_path).await?;
    let file_name = file_path.file_name().unwrap().to_str().unwrap();

    client
        .put_object()
        .bucket(bucket)
        .key(file_name)
        .body(body)
        .send()
        .await?;

    Ok(())
}
