public class StockMarketAnalyzer {

    public static void main(String[] args) {
        StockStreamingService streamingService = new StockStreamingService();
        StockAnalysisService analysisService = new StockAnalysisService();
        streamingService.subscribe(analysisService);

        // Simulate streaming data
        ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();
        executor.submit(() -> {
            while (true) {
                streamingService.publishStockData(new StockData("AAPL", 150.25, Instant.now()));
                streamingService.publishStockData(new StockData("MSFT", 300.50, Instant.now()));
                Thread.sleep(1000);
            }
        });

        // REST API would be implemented here (e.g., using Javalin, Spring Boot, etc.)
    }
}

record StockData(String symbol, double price, Instant timestamp) {}

class StockStreamingService extends SubmissionPublisher<StockData> {
    public void publishStockData(StockData data) {
        submit(data);
    }
}

class StockAnalysisService implements Flow.Subscriber<StockData> {
    private final Map<String, List<Double>> priceHistory = new ConcurrentHashMap<>();
    private Flow.Subscription subscription;

    @Override
    public void onSubscribe(Flow.Subscription subscription) {
        this.subscription = subscription;
        subscription.request(1);
    }

    @Override
    public void onNext(StockData item) {
        priceHistory.computeIfAbsent(item.symbol(), k -> new java.util.ArrayList<>()).add(item.price());
        calculateMovingAverage(item.symbol());
        checkFluctuations(item.symbol());
        subscription.request(1);
    }

    @Override
    public void onError(Throwable throwable) {
        System.err.println("Error in stock analysis: " + throwable.getMessage());
    }

    @Override
    public void onComplete() {
        System.out.println("Stock analysis completed");
    }

    private void calculateMovingAverage(String symbol) {
        List<Double> prices = priceHistory.get(symbol);
        if (prices.size() >= 5) {
            double movingAvg = prices.stream()
                .skip(prices.size() - 5)
                .collect(Collectors.averagingDouble(Double::doubleValue));
            System.out.printf("Moving average for %s: %.2f%n", symbol, movingAvg);
        }
    }

    private void checkFluctuations(String symbol) {
        List<Double> prices = priceHistory.get(symbol);
        if (prices.size() >= 2) {
            double last = prices.get(prices.size() - 1);
            double prev = prices.get(prices.size() - 2);
            double change = ((last - prev) / prev) * 100;
            if (Math.abs(change) >= 1.0) {
                System.out.printf("Alert: %s price changed by %.2f%%%n", symbol, change);
            }
        }
    }
}
