use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Instant;

use async_std::fs;
use async_std::task;
use futures::stream::StreamExt;
use image::imageops::FilterType;
use image::{DynamicImage, ImageFormat};
use tokio::sync::Semaphore;

#[derive(Debug)]
struct ImageResizeConfig {
    width: u32,
    height: u32,
}

async fn process_image(
    source_path: PathBuf,
    dest_path: PathBuf,
    resize_config: Option<ImageResizeConfig>,
    semaphore: Arc<Semaphore>,
) -> Result<(), Box<dyn std::error::Error>> {
    let _permit = semaphore.acquire().await?;

    let img = image::open(&source_path)?;
    let processed_img = match resize_config {
        Some(config) => {
            let (width, height) = if img.width() > img.height() {
                (config.width, (img.height() as f32 * (config.width as f32 / img.width() as f32)) as u32)
            } else {
                ((img.width() as f32 * (config.height as f32 / img.height() as f32)) as u32, config.height)
            };
            img.resize(width, height, FilterType::Lanczos3)
        }
        None => img,
    };

    let format = match source_path.extension().and_then(|ext| ext.to_str()) {
        Some("jpg") | Some("jpeg") => ImageFormat::Jpeg,
        Some("png") => ImageFormat::Png,
        _ => return Err("Unsupported image format".into()),
    };

    processed_img.save_with_format(&dest_path, format)?;
    fs::remove_file(&source_path).await?;
    Ok(())
}

async fn migrate_images(
    source_dir: &Path,
    dest_dir: &Path,
    resize_config: Option<ImageResizeConfig>,
    max_concurrent: usize,
) -> Result<(), Box<dyn std::error::Error>> {
    fs::create_dir_all(dest_dir).await?;

    let semaphore = Arc::new(Semaphore::new(max_concurrent));
    let mut tasks = vec![];

    let mut entries = fs::read_dir(source_dir).await?;
    while let Some(entry) = entries.next().await {
        let entry = entry?;
        let path = entry.path();
        if path.is_file() {
            if let Some(ext) = path.extension().and_then(|ext| ext.to_str()) {
                if ext == "jpg" || ext == "jpeg" || ext == "png" {
                    let dest_path = dest_dir.join(path.file_name().unwrap());
                    let resize_config = resize_config.clone();
                    let semaphore = semaphore.clone();

                    tasks.push(task::spawn(async move {
                        match process_image(path, dest_path, resize_config, semaphore).await {
                            Ok(_) => println!("Processed successfully"),
                            Err(e) => eprintln!("Error processing image: {}", e),
                        }
                    }));
                }
            }
        }
    }

    futures::future::join_all(tasks).await;
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("Usage: {} <source_dir> <dest_dir> [width height]", args[0]);
        std::process::exit(1);
    }

    let source_dir = Path::new(&args[1]);
    let dest_dir = Path::new(&args[2]);
    let resize_config = if args.len() == 5 {
        Some(ImageResizeConfig {
            width: args[3].parse()?,
            height: args[4].parse()?,
        })
    } else {
        None
    };

    let start = Instant::now();
    migrate_images(source_dir, dest_dir, resize_config, 10).await?;
    println!("Migration completed in {:?}", start.elapsed());

    Ok(())
}
