use std::fs::File;
use std::io::{self, BufRead, BufReader};
use std::path::Path;
use std::sync::mpsc;
use std::thread;
use flate2::Compression;
use flate2::write::GzEncoder;

fn compress_file(path: &str) -> io::Result<()> {
    let input_file = File::open(path)?;
    let output_path = format!("{}.gz", path);
    let output_file = File::create(output_path)?;

    let mut encoder = GzEncoder::new(output_file, Compression::default());
    io::copy(&mut BufReader::new(input_file), &mut encoder)?;
    encoder.finish()?;
    Ok(())
}

fn main() {
    let (tx, rx) = mpsc::channel();
    let mut handles = vec![];

    // Spawn a bounded number of worker threads
    for _ in 0..num_cpus::get() {
        let rx = rx.clone();
        let handle = thread::spawn(move || {
            for path in rx {
                if let Err(e) = compress_file(&path) {
                    eprintln!("Failed to compress {}: {}", path, e);
                }
            }
        });
        handles.push(handle);
    }

    // Read filenames from stdin and send to workers
    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        if let Ok(path) = line {
            if Path::new(&path).exists() {
                tx.send(path).unwrap();
            } else {
                eprintln!("File not found: {}", path);
            }
        }
    }

    // Drop the sender to signal workers to exit
    drop(tx);

    // Wait for all workers to finish
    for handle in handles {
        handle.join().unwrap();
    }
}
