```java
import java.io.*;
import java.net.URI;
import java.net.http.*;
import java.net.http.HttpResponse.BodyHandlers;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
import javax.json.*;
import org.apache.pdfbox.pdmodel.PDDocument;
import org.apache.pdfbox.text.PDFTextStripper;
import org.apache.poi.xwpf.extractor.XWPFWordExtractor;
import org.apache.poi.xwpf.usermodel.XWPFDocument;

public class DocumentPreviewService {
    private static final HttpClient httpClient = HttpClient.newHttpClient();

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/preview", new PreviewHandler());
        server.start();
    }

    static class PreviewHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("POST".equals(exchange.getRequestMethod())) {
                try (InputStream is = exchange.getRequestBody()) {
                    Path tempFile = Files.createTempFile("upload", ".tmp");
                    Files.copy(is, tempFile, StandardCopyOption.REPLACE_EXISTING);

                    DocumentSummary summary = processFile(tempFile);
                    String response = summary.toJson();

                    exchange.getResponseHeaders().set("Content-Type", "application/json");
                    exchange.sendResponseHeaders(200, response.getBytes().length);
                    try (OutputStream os = exchange.getResponseBody()) {
                        os.write(response.getBytes());
                    }
                    Files.deleteIfExists(tempFile);
                }
            } else {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
            }
        }
    }

    static DocumentSummary processFile(Path filePath) throws IOException {
        String fileName = filePath.getFileName().toString();
        String fileType = detectFileType(fileName);
        String content = extractText(filePath, fileType);
        String language = detectLanguage(content);
        int wordCount = countWords(content);

        return new DocumentSummary(
            fileName,
            fileType,
            language,
            wordCount,
            content.substring(0, Math.min(200, content.length()))
        );
    }

    static String detectFileType(String fileName) {
        if (fileName.toLowerCase().endsWith(".pdf")) return "PDF";
        if (fileName.toLowerCase().endsWith(".docx")) return "DOCX";
        if (fileName.toLowerCase().endsWith(".txt")) return "TXT";
        return "UNKNOWN";
    }

    static String extractText(Path filePath, String fileType) throws IOException {
        switch (fileType) {
            case "PDF":
                try (PDDocument doc = PDDocument.load(filePath.toFile())) {
                    return new PDFTextStripper().getText(doc);
                }
            case "DOCX":
                try (XWPFDocument doc = new XWPFDocument(Files.newInputStream(filePath))) {
                    return new XWPFWordExtractor(doc).getText();
                }
            case "TXT":
                Charset charset = StandardCharsets.UTF_8;
                try {
                    charset = Charset.forName(Files.newBufferedReader(filePath).getEncoding());
                } catch (Exception e) {
                    charset = StandardCharsets.UTF_8;
                }
                return Files.readString(filePath, charset);
            default:
                throw new IOException("Unsupported file type");
        }
    }

    static String detectLanguage(String content) {
        // Basic language detection based on common words
        if (content.isEmpty()) return "UNKNOWN";

        String lowerContent = content.toLowerCase();
        if (lowerContent.contains(" the ") || lowerContent.contains(" and ")) return "EN";
        if (lowerContent.contains(" el ") || lowerContent.contains(" y ")) return "ES";
        if (lowerContent.contains(" le ") || lowerContent.contains(" et ")) return "FR";
        if (lowerContent.contains(" der ") || lowerContent.contains(" und ")) return "DE";
        return "UNKNOWN";
    }

    static int countWords(String content) {
        if (content == null || content.isEmpty()) return 0;
        return content.split("\\s+").length;
    }

    static class DocumentSummary {
        String fileName;
        String fileType;
        String language;
        int wordCount;
        String preview;

        public DocumentSummary(String fileName, String fileType, String language, int wordCount, String preview) {
            this.fileName = fileName;
            this.fileType = fileType;
            this.language = language;
            this.wordCount = wordCount;
            this.preview = preview;
        }

        public String toJson() {
            return Json.createObjectBuilder()
                .add("fileName", fileName)
                .add("fileType", fileType)
                .add("language", language)
                .add("wordCount", wordCount)
                .add("preview", preview)
                .build()
                .toString();
        }
    }
}
